import { interpolate, useCurrentFrame } from "remotion";
import { ReactNode } from "react";

interface HologramBoxProps {
  children: ReactNode;
  delay?: number;
  color?: string;
}

export const HologramBox: React.FC<HologramBoxProps> = ({
  children,
  delay = 0,
  color = "#00FFFF",
}) => {
  const frame = useCurrentFrame();

  const opacity = interpolate(frame - delay, [0, 20], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const glitch = Math.sin(frame * 0.3) * 2;
  const scanLine = (frame * 2) % 100;

  return (
    <div
      style={{
        position: "relative",
        background:
          "linear-gradient(135deg, rgba(0,0,0,0.8) 0%, rgba(0,20,40,0.8) 100%)",
        border: `1px solid ${color}`,
        borderRadius: 12,
        opacity,
        transform: `translateX(${glitch}px)`,
        boxShadow: `
          0 0 20px ${color}40,
          inset 0 0 30px ${color}10
        `,
        overflow: "hidden",
      }}
    >
      {children}

      {/* Scan line */}
      <div
        style={{
          position: "absolute",
          width: "100%",
          height: 2,
          top: `${scanLine}%`,
          background: `linear-gradient(90deg, transparent, ${color}50, transparent)`,
          pointerEvents: "none",
        }}
      />

      {/* Glowing corners */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: 20,
          height: 20,
          borderTop: `2px solid ${color}`,
          borderLeft: `2px solid ${color}`,
        }}
      />
      <div
        style={{
          position: "absolute",
          top: 0,
          right: 0,
          width: 20,
          height: 20,
          borderTop: `2px solid ${color}`,
          borderRight: `2px solid ${color}`,
        }}
      />
      <div
        style={{
          position: "absolute",
          bottom: 0,
          left: 0,
          width: 20,
          height: 20,
          borderBottom: `2px solid ${color}`,
          borderLeft: `2px solid ${color}`,
        }}
      />
      <div
        style={{
          position: "absolute",
          bottom: 0,
          right: 0,
          width: 20,
          height: 20,
          borderBottom: `2px solid ${color}`,
          borderRight: `2px solid ${color}`,
        }}
      />
    </div>
  );
};

