import { AbsoluteFill, interpolate, useCurrentFrame } from "remotion";
import { useMemo } from "react";

interface Star {
  x: number;
  y: number;
  size: number;
  speed: number;
  opacity: number;
}

export const StarField: React.FC = () => {
  const frame = useCurrentFrame();

  const stars: Star[] = useMemo(() => {
    const seededRandom = (seed: number) => {
      const x = Math.sin(seed * 9301 + 49297) * 49297;
      return x - Math.floor(x);
    };
    return Array.from({ length: 500 }, (_, i) => ({
      x: seededRandom(i * 1) * 100,
      y: seededRandom(i * 2 + 100) * 100,
      size: seededRandom(i * 3 + 200) * 3 + 1,
      speed: seededRandom(i * 4 + 300) * 2 + 0.5,
      opacity: seededRandom(i * 5 + 400) * 0.5 + 0.5,
    }));
  }, []);

  return (
    <AbsoluteFill style={{ backgroundColor: "#000010" }}>
      {stars.map((star, i) => {
        const progress = (frame * star.speed) % 200;
        const scale = interpolate(progress, [0, 200], [0.1, 3]);
        const opacity = interpolate(
          progress,
          [0, 100, 200],
          [0, star.opacity, 0]
        );

        return (
          <div
            key={i}
            style={{
              position: "absolute",
              left: `${star.x}%`,
              top: `${star.y}%`,
              width: star.size * scale,
              height: star.size * scale,
              borderRadius: "50%",
              backgroundColor: "#fff",
              opacity,
              boxShadow: `0 0 ${star.size * 2}px #fff`,
            }}
          />
        );
      })}

      {/* Vignette effect */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "radial-gradient(ellipse at center, transparent 0%, rgba(0,0,20,0.8) 100%)",
        }}
      />
    </AbsoluteFill>
  );
};

