import {
  AbsoluteFill,
  interpolate,
  useCurrentFrame,
  Sequence,
} from "remotion";

const CRAWL_TEXT = `Le SEO régnait en maître absolu.
Les marketeurs optimisaient leurs sites
pour un seul empire : Google.

Mais les temps ont changé.

Une nouvelle force a émergé.
ChatGPT, Claude, Gemini, Perplexity...
Les moteurs de réponse IA
ont pris le pouvoir.

Le référencement tel que vous
le connaissiez est devenu OBSOLÈTE.

Les utilisateurs ne cliquent plus.
Ils DEMANDENT aux IA.
Et les IA CITENT leurs sources.

Une question se pose désormais :

VOTRE SITE SERA-T-IL CITÉ ?

C'est là qu'intervient
une nouvelle espérance...`;

export const OpeningCrawl: React.FC = () => {
  const frame = useCurrentFrame();

  const scrollY = interpolate(frame, [0, 360], [100, -250], {
    extrapolateRight: "clamp",
  });

  const opacity = interpolate(frame, [0, 30, 320, 360], [0, 1, 1, 0]);

  return (
    <AbsoluteFill
      style={{
        backgroundColor: "transparent",
        perspective: "400px",
        perspectiveOrigin: "50% 100%",
        overflow: "hidden",
      }}
    >
      {/* "A long time ago..." intro text */}
      <Sequence from={0} durationInFrames={90}>
        <div
          style={{
            position: "absolute",
            top: "40%",
            width: "100%",
            textAlign: "center",
            color: "#4BE0F0",
            fontFamily: "Orbitron, sans-serif",
            fontSize: 36,
            letterSpacing: 4,
            opacity: interpolate(frame, [0, 30, 60, 90], [0, 1, 1, 0]),
          }}
        >
          IL Y A BIEN LONGTEMPS, DANS UNE GALAXIE MARKETING...
        </div>
      </Sequence>

      {/* Main crawl text */}
      <Sequence from={90}>
        <div
          style={{
            position: "absolute",
            top: "20%",
            left: "50%",
            width: "70%",
            transform: `translateX(-50%) rotateX(60deg) translateY(${scrollY}%)`,
            transformOrigin: "50% 100%",
            opacity,
          }}
