              letterSpacing: 2,
              textShadow: "0 0 20px rgba(255, 215, 0, 0.5)",
              whiteSpace: "pre-line",
            }}
          >
            {CRAWL_TEXT}
          </p>
        </div>
      </Sequence>
    </AbsoluteFill>
  );
};

