import { AbsoluteFill, useCurrentFrame, interpolate } from "remotion";

const STATS = [
  { value: 50, suffix: "+", label: "Crit\u00E8res analys\u00E9s", color: "#00FFFF" },
  { value: 10, suffix: "x", label: "Plus de citations", color: "#FFD700" },
  { value: 92, suffix: "%", label: "Clients satisfaits", color: "#4ECDC4" },
  { value: 24, suffix: "/7", label: "Monitoring continu", color: "#FF6B6B" },
];

export const StatsScene: React.FC = () => {
  const frame = useCurrentFrame();

  return (
    <AbsoluteFill
      style={{
        background: "linear-gradient(180deg, #000 0%, #001030 100%)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div style={{ display: "flex", gap: 80 }}>
        {STATS.map((stat, index) => {
          const delay = index * 15;
          const progress = Math.min(
            1,
            Math.max(0, (frame - delay) / 45)
          );
          const currentValue = Math.round(stat.value * progress);

          const scale = interpolate(frame - delay, [0, 15], [0.5, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          });

          const opacity = interpolate(frame - delay, [0, 15], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          });

          return (
            <div
              key={index}
              style={{
                textAlign: "center",
                transform: `scale(${scale})`,
                opacity,
              }}
            >
              <p
                style={{
                  fontFamily: "Orbitron, sans-serif",
                  fontSize: 96,
                  fontWeight: 900,
                  color: stat.color,
                  textShadow: `0 0 40px ${stat.color}`,
                }}
              >
                {currentValue}
                {stat.suffix}
              </p>
              <p style={{ fontSize: 24, color: "#888", marginTop: 10 }}>
