import {
  AbsoluteFill,
  interpolate,
  useCurrentFrame,
  spring,
  useVideoConfig,
} from "remotion";

export const LogoReveal: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const scale = spring({
    frame,
    fps,
    config: { damping: 12, stiffness: 100 },
  });

  const glitchOffset = Math.sin(frame * 0.5) * 2;
  const scanLine = (frame * 3) % 100;
  const flicker = 0.8 + Math.sin(frame * 0.8) * 0.2;

  return (
    <AbsoluteFill
      style={{
        backgroundColor: "transparent",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      {/* Hologram circle */}
      <div
        style={{
          position: "absolute",
          width: 600,
          height: 600,
          borderRadius: "50%",
          border: "2px solid rgba(0, 255, 255, 0.3)",
          boxShadow: `
            0 0 60px rgba(0, 255, 255, 0.3),
            inset 0 0 60px rgba(0, 255, 255, 0.1)
          `,
          transform: `scale(${scale})`,
        }}
      />

      {/* Main logo */}
      <div
        style={{
          transform: `scale(${scale}) translateX(${glitchOffset}px)`,
          opacity: flicker,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
        }}
      >
        <h1
          style={{
            fontFamily: "Orbitron, sans-serif",
            fontSize: 120,
            fontWeight: 900,
            color: "transparent",
            background:
              "linear-gradient(180deg, #00FFFF 0%, #0080FF 50%, #00FFFF 100%)",
            backgroundClip: "text",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            letterSpacing: 8,
            filter: "drop-shadow(0 0 20px rgba(0, 255, 255, 0.8))",
          }}
        >
          CITEDBY
        </h1>

        <h2
          style={{
            fontFamily: "Orbitron, sans-serif",
            fontSize: 80,
            fontWeight: 300,
            color: "#FFD700",
            textAlign: "center",
            marginTop: -20,
            textShadow: `
              0 0 20px rgba(255, 215, 0, 0.8),
              0 0 40px rgba(255, 215, 0, 0.6)
            `,
            letterSpacing: 20,
          }}
        >
          .AI
        </h2>
      </div>

      {/* Holographic scan line */}
      <div
        style={{
          position: "absolute",
          width: "100%",
          height: 2,
          top: `${scanLine}%`,
          background:
            "linear-gradient(90deg, transparent, rgba(0, 255, 255, 0.5), transparent)",
