import { SolutionScene } from "./sequences/05-SolutionScene";
import { FeaturesShowcase } from "./sequences/06-FeaturesShowcase";
import { StatsScene } from "./sequences/07-StatsScene";
import { CallToAction } from "./sequences/08-CallToAction";

export const CitedByPromoVideo: React.FC = () => {
  return (
    <AbsoluteFill style={{ backgroundColor: "#000" }}>
      {/* Permanent star field background */}
      <StarField />

      {/* Sequences timeline */}
      <Sequence from={0} durationInFrames={450} name="Opening Crawl">
        <OpeningCrawl />
      </Sequence>

      <Sequence from={450} durationInFrames={150} name="Logo Reveal">
        <LogoReveal />
      </Sequence>

      <Sequence from={600} durationInFrames={240} name="Problem">
        <ProblemScene />
      </Sequence>

      <Sequence from={840} durationInFrames={210} name="Solution">
        <SolutionScene />
      </Sequence>

      <Sequence from={1050} durationInFrames={390} name="Features">
        <FeaturesShowcase />
      </Sequence>

      <Sequence from={1440} durationInFrames={150} name="Stats">
        <StatsScene />
      </Sequence>

      <Sequence from={1590} durationInFrames={210} name="Call To Action">
        <CallToAction />
      </Sequence>
    </AbsoluteFill>
  );
};

