import { Composition } from "remotion";
import { HelloWorld } from "./HelloWorld";
import { CommercialLaunch } from "./CommercialLaunch";
import { CitedByPromoVideo } from "./src/Video";
import "./src/styles/global.css";

export const RemotionRoot: React.FC = () => {
  return (
    <>
      {/* NEW: Star Wars style promo — 60s @ 1920x1080 */}
      <Composition
        id="CitedByPromo"
        component={CitedByPromoVideo}
        durationInFrames={60 * 30}
        fps={30}
        width={1920}
        height={1080}
      />

      {/* NEW: Short version for social media — 30s square */}
      <Composition
        id="CitedByPromoShort"
        component={CitedByPromoVideo}
        durationInFrames={30 * 30}
        fps={30}
        width={1080}
        height={1080}
      />

      {/* Existing compositions */}
      <Composition
        id="CommercialLaunch"
        component={CommercialLaunch}
        durationInFrames={1620}
        fps={30}
        width={1920}
        height={1080}
      />
      <Composition
        id="HelloWorld"
        component={HelloWorld}
        durationInFrames={150}
        fps={30}
        width={1920}
        height={1080}
      />
    </>
  );
};

