import { interpolate, useCurrentFrame } from "remotion";

interface AnimatedListItem {
  icon?: string;
  text: string;
  highlight?: string;
}

interface AnimatedListProps {
  items: AnimatedListItem[];
  delay?: number;
  stagger?: number;
  color?: string;
  fontSize?: number;
}

export const AnimatedList: React.FC<AnimatedListProps> = ({
  items,
  delay = 0,
  stagger = 12,
  color = "#00FFFF",
  fontSize = 28,
}) => {
  const frame = useCurrentFrame();

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
      {items.map((item, i) => {
        const itemDelay = delay + i * stagger;

        const opacity = interpolate(frame - itemDelay, [0, 15], [0, 1], {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        });

        const translateX = interpolate(frame - itemDelay, [0, 15], [-40, 0], {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        });

        return (
          <div
            key={i}
            style={{
              display: "flex",
              alignItems: "center",
              gap: 16,
              opacity,
              transform: `translateX(${translateX}px)`,
            }}
          >
            {/* Bullet / icon */}
            <span style={{ fontSize: fontSize + 4, flexShrink: 0 }}>
              {item.icon || "\u25B8"}
            </span>

            <p
              style={{
                fontFamily: "Inter, sans-serif",
                fontSize,
                color: "#ccc",
                lineHeight: 1.4,
              }}
            >
              {item.text}
              {item.highlight && (
                <span
                  style={{ color, fontWeight: 600, marginLeft: 6 }}
                >
                  {item.highlight}
                </span>
              )}
            </p>
          </div>
        );
      })}
    </div>
  );
};

