          fontFamily: "Orbitron, sans-serif",
          fontSize: 24,
          color: "#FF6B6B",
          letterSpacing: 4,
          opacity: interpolate(frame, [70, 100], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
        }}
      >
        VOTRE SITE SERA-T-IL VISIBLE ?
      </p>
    </AbsoluteFill>
  );
};

/* ─── Scene 2 : Logo + explication ─── */
const PresentationScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const scale = spring({ frame, fps, config: { damping: 12 } });
  const flicker = 0.85 + Math.sin(frame * 0.6) * 0.15;

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 40,
      }}
    >
      {/* Logo */}
      <div style={{ transform: `scale(${scale})`, opacity: flicker }}>
