            description={a.desc}
            color={a.color}
            delay={20 + i * 18}
          />
        ))}
      </div>
    </AbsoluteFill>
  );
};

/* ─── Scene 5 : CTA ─── */
const CtaScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const scale = spring({ frame, fps, config: { damping: 12 } });
  const pulse = 1 + Math.sin(frame * 0.15) * 0.04;

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 40,
      }}
    >
      <p
        style={{
          fontFamily: "Orbitron, sans-serif",
          fontSize: 36,
          color: "#ccc",
          opacity: interpolate(frame, [0, 25], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
        }}
      >
        {"PR\u00CAT \u00C0 \u00CATRE CIT\u00C9 PAR LES IA ?"}
      </p>

      <div style={{ transform: `scale(${scale * pulse})` }}>
        <div
          style={{
            padding: "28px 70px",
            background: "linear-gradient(135deg, #7c3aed, #6d28d9)",
            borderRadius: 60,
            boxShadow:
              "0 0 40px rgba(124,58,237,0.5), 0 0 80px rgba(124,58,237,0.25)",
          }}
        >
          <p
            style={{
              fontFamily: "Orbitron, sans-serif",
              fontSize: 32,
              fontWeight: "bold",
              color: "#fff",
              letterSpacing: 3,
            }}
          >
            PREMIER AUDIT GRATUIT
          </p>
        </div>
      </div>

      <p
        style={{
          fontFamily: "Orbitron, sans-serif",
          fontSize: 28,
          color: "#FFD700",
          letterSpacing: 6,
          marginTop: 20,
          textShadow: "0 0 20px rgba(255,215,0,0.4)",
          opacity: interpolate(frame, [30, 55], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
        }}
      >
        CITEDBY.AI
      </p>
    </AbsoluteFill>
  );
};

/* ─── Main Composition ─── */
export const WhatIsCitedBy: React.FC = () => {
  return (
    <AbsoluteFill style={{ backgroundColor: "#000" }}>
      <StarField />

      <Sequence from={0} durationInFrames={150} name="Hook">
        <HookScene />
      </Sequence>

      <Sequence from={150} durationInFrames={300} name="Presentation">
        <PresentationScene />
      </Sequence>

      <Sequence from={450} durationInFrames={300} name="Pillars">
        <PillarScene />
      </Sequence>

      <Sequence from={750} durationInFrames={300} name="Audience">
        <AudienceScene />
      </Sequence>

      <Sequence from={1050} durationInFrames={300} name="CTA">
        <CtaScene />
      </Sequence>
    </AbsoluteFill>
  );
};

