            delay={0}
          />
        </div>
      </Sequence>
    </AbsoluteFill>
  );
};

/* ─── Scene 4 : Tableau comparatif ─── */
const ComparisonScene: React.FC = () => {
  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 60,
      }}
