      <div style={{ marginTop: 50 }}>
        <ComparisonTable
          leftTitle="SEO"
          rightTitle="AEO"
          leftColor="#FF6B6B"
          rightColor="#00FFFF"
          delay={20}
          rows={[
            { label: "Objectif", left: "Ranking SERP", right: "Citation IA" },
            { label: "Cible", left: "10 liens bleus", right: "R\u00E9ponse unique" },
            { label: "M\u00E9trique", left: "Position + CTR", right: "Share of Voice IA" },
            { label: "Contenu", left: "Long-format SEO", right: "Answer-First structur\u00E9" },
            { label: "Technique", left: "Balises meta + liens", right: "Schema.org + llms.txt" },
            { label: "Signal", left: "Backlinks", right: "Entity Authority + E-E-A-T" },
            { label: "R\u00E9sultat", left: "Clics organiques", right: "Citation directe" },
            { label: "Tendance", left: "\u2198 En d\u00E9clin", right: "\u2197 En explosion" },
          ]}
        />
      </div>
    </AbsoluteFill>
  );
};

/* ─── Scene 5 : Conclusion ─── */
const ConclusionScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const scale = spring({ frame, fps, config: { damping: 12 } });

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 50,
      }}
    >
      <p
        style={{
          fontFamily: "Orbitron, sans-serif",
          fontSize: 44,
          color: "#fff",
          textAlign: "center",
          maxWidth: 1000,
          lineHeight: 1.5,
          opacity: interpolate(frame, [0, 30], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
        }}
      >
        {"Le SEO ne suffit plus.\nL'AEO est le nouveau standard."}
      </p>

      <div style={{ transform: `scale(${scale})` }}>
        <div
          style={{
            padding: "24px 60px",
            background: "linear-gradient(135deg, #00FFFF, #0080FF)",
            borderRadius: 50,
            boxShadow: "0 0 40px rgba(0,255,255,0.4)",
          }}
        >
          <p
            style={{
              fontFamily: "Orbitron, sans-serif",
              fontSize: 28,
              fontWeight: "bold",
              color: "#000",
              letterSpacing: 3,
            }}
          >
            {"PASSEZ \u00C0 L'AEO AVEC CITEDBY.AI"}
          </p>
        </div>
      </div>

      <p
        style={{
          fontFamily: "Orbitron, sans-serif",
          fontSize: 24,
          color: "#FFD700",
          letterSpacing: 6,
          opacity: interpolate(frame, [40, 65], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
        }}
      >
        CITEDBY.AI
      </p>
    </AbsoluteFill>
  );
};

/* ─── Main ─── */
export const SeoVsAeo: React.FC = () => {
  return (
    <AbsoluteFill style={{ backgroundColor: "#000" }}>
      <StarField />

      <Sequence from={0} durationInFrames={240} name="Hook">
        <HookScene />
      </Sequence>

      <Sequence from={240} durationInFrames={300} name="SEO Classique">
        <SeoScene />
      </Sequence>

      <Sequence from={540} durationInFrames={300} name="AEO Futur">
        <AeoScene />
      </Sequence>

      <Sequence from={840} durationInFrames={420} name="Comparatif">
        <ComparisonScene />
      </Sequence>

      <Sequence from={1260} durationInFrames={240} name="Conclusion">
        <ConclusionScene />
      </Sequence>
    </AbsoluteFill>
  );
};

