import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  interpolate,
  spring,
  useVideoConfig,
} from "remotion";
import { StarField } from "../sequences/01-StarField";
import { SectionTitle } from "../components/SectionTitle";
import { HologramBox } from "../components/HologramBox";
import { ProgressRing } from "../components/ProgressRing";
import { NeonText } from "../components/NeonText";

/* ─── Scene 1 : Le constat ─── */
const ConstatScene: React.FC = () => {
  const frame = useCurrentFrame();

  const stats = [
    { value: -40, label: "Clics organiques", suffix: "%", color: "#FF0040" },
    { value: 65, label: "Recherches sans clic", suffix: "%", color: "#FF6B6B" },
    { value: 50, label: "Recherches via IA en 2026", suffix: "%", color: "#FFD700" },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 80,
      }}
    >
      <SectionTitle
        title="LE CONSTAT"
        subtitle="Le paysage digital a chang\u00E9"
        color="#FF0040"
      />

      <div style={{ display: "flex", gap: 80, marginTop: 100 }}>
        {stats.map((stat, i) => {
          const delay = 30 + i * 20;
          const opacity = interpolate(frame - delay, [0, 20], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          });

          const countTo = Math.abs(stat.value);
          const progress = interpolate(frame - delay, [0, 40], [0, countTo], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          });

          return (
            <div key={i} style={{ textAlign: "center", opacity }}>
              <p
                style={{
                  fontFamily: "Orbitron, sans-serif",
                  fontSize: 80,
                  fontWeight: 900,
                  color: stat.color,
                  textShadow: `0 0 30px ${stat.color}50`,
                }}
              >
                {stat.value < 0 ? "-" : ""}
                {Math.round(progress)}
                {stat.suffix}
              </p>
              <p style={{ fontSize: 22, color: "#888", marginTop: 10 }}>
                {stat.label}
              </p>
            </div>
          );
        })}
      </div>

      <Sequence from={120}>
        <div
          style={{
            position: "absolute",
            bottom: 140,
            width: "100%",
            textAlign: "center",
          }}
        >
          <p
            style={{
              fontFamily: "Orbitron, sans-serif",
              fontSize: 30,
              color: "#fff",
              opacity: interpolate(frame - 120, [0, 25], [0, 1], {
                extrapolateLeft: "clamp",
                extrapolateRight: "clamp",
              }),
            }}
          >
            {"Les IA ne classent pas. Elles "}
            <span style={{ color: "#00FFFF" }}>CITENT</span>.
          </p>
        </div>
      </Sequence>
    </AbsoluteFill>
  );
};

/* ─── Scene 2 : 3 piliers ─── */
