  const pillars = [
    {
      icon: "\uD83C\uDF10",
      title: "IDENTIT\u00C9",
      subtitle: "Knowledge Graph",
      desc: "Votre marque reconnue comme entit\u00E9 nomm\u00E9e",
      color: "#00FFFF",
    },
    {
      icon: "\uD83E\uDDE0",
      title: "S\u00C9MANTIQUE",
      subtitle: "RAG-Ready",
      desc: "Answer-First + JSON-LD pour l'ingestion IA",
