      />

      <div style={{ display: "flex", gap: 50, marginTop: 80, padding: "0 100px" }}>
        {pillars.map((p, i) => (
          <Sequence key={i} from={20 + i * 20}>
            <HologramBox color={p.color} delay={0}>
              <div style={{ padding: "40px 35px", textAlign: "center", minHeight: 300 }}>
                <span style={{ fontSize: 56 }}>{p.icon}</span>
                <p
                  style={{
                    fontFamily: "Orbitron, sans-serif",
                    fontSize: 28,
                    color: p.color,
                    marginTop: 20,
                    fontWeight: 700,
                  }}
                >
                  {p.title}
                </p>
                <p
                  style={{
                    fontFamily: "Orbitron, sans-serif",
