                  }}
                >
                  {p.desc}
                </p>
              </div>
            </HologramBox>
          </Sequence>
        ))}
      </div>
    </AbsoluteFill>
  );
};

/* ─── Scene 3 : 10 categories ─── */
const CategoriesScene: React.FC = () => {
  const categories = [
    { name: "Infrastructure", score: 90, color: "#00FFFF" },
    { name: "S\u00E9mantique", score: 85, color: "#3b82f6" },
