    { name: "Autorit\u00E9", score: 82, color: "#a855f7" },
    { name: "Donn\u00E9es structur\u00E9es", score: 70, color: "#4ECDC4" },
    { name: "Formatage GEO", score: 75, color: "#f43f5e" },
    { name: "Confiance", score: 88, color: "#10b981" },
    { name: "Fra\u00EEcheur", score: 65, color: "#FF6B6B" },
