  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 50,
      }}
    >
      <SectionTitle
        title="50 CRIT\u00C8RES \u2014 10 CAT\u00C9GORIES"
        subtitle="L'audit AEO le plus complet du march\u00E9"
        color="#00FFFF"
      />

      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          justifyContent: "center",
          gap: 30,
          marginTop: 50,
          padding: "0 120px",
        }}
      >
        {categories.map((cat, i) => (
          <ProgressRing
            key={i}
            value={cat.score}
            label={cat.name}
            color={cat.color}
            delay={15 + i * 8}
            size={140}
          />
        ))}
      </div>
    </AbsoluteFill>
  );
};

/* ─── Scene 4 : T\u00E9moignages ─── */
const TestimonialsScene: React.FC = () => {
  const testimonials = [
    {
      quote: "De 0 citation \u00E0 recommand\u00E9 par ChatGPT en 3 semaines",
      name: "Marie Dubois",
      role: "CMO, TechFlow SaaS",
      color: "#10b981",
    },
    {
      quote: "Schema.org et Source of Truth ont tout transform\u00E9",
      name: "Thomas Martin",
      role: "Head of SEO, GreenGarden",
      color: "#FFD700",
    },
    {
      quote: "Le dashboard de monitoring est une mine d'or",
      name: "Sophie Laurent",
      role: "Directrice Digitale, OmniMedia",
      color: "#a855f7",
    },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 80,
      }}
    >
      <SectionTitle title="ILS NOUS FONT CONFIANCE" color="#FFD700" />

      <div
        style={{
          display: "flex",
          gap: 40,
          marginTop: 80,
          padding: "0 120px",
        }}
      >
        {testimonials.map((t, i) => (
          <Sequence key={i} from={15 + i * 25}>
            <HologramBox color={t.color} delay={0}>
              <div style={{ padding: "35px 30px", minWidth: 350, minHeight: 200 }}>
                <p
                  style={{
                    fontSize: 22,
                    color: "#ccc",
                    fontStyle: "italic",
                    lineHeight: 1.6,
                    marginBottom: 20,
                  }}
                >
                  {`\u00AB ${t.quote} \u00BB`}
                </p>
                <p
                  style={{
                    fontFamily: "Orbitron, sans-serif",
                    fontSize: 16,
                    color: t.color,
                    fontWeight: 600,
                  }}
                >
                  {t.name}
                </p>
                <p style={{ fontSize: 14, color: "#666", marginTop: 4 }}>
                  {t.role}
                </p>
