            </HologramBox>
          </Sequence>
        ))}
      </div>

      {/* Trust badges */}
      <Sequence from={100}>
        <div
          style={{
            position: "absolute",
            bottom: 100,
            display: "flex",
            gap: 50,
            opacity: interpolate(0, [0, 1], [0.6, 0.6]),
          }}
        >
          {["RGPD", "SSL", "99.9% Uptime", "Made in France"].map((badge, i) => (
