/**
 * Template 5: "Comment \u00E7a marche ?"
 * Duration: 45 seconds (1350 frames @ 30fps)
 *
 * Timeline:
 *   0-5s    (0-150)      Accroche : "3 \u00E9tapes. 24h. Vous \u00EAtes cit\u00E9."
 *   5-17s   (150-510)    \u00C9tape 1 : Analyse de perception
 *   17-29s  (510-870)    \u00C9tape 2 : G\u00E9n\u00E9ration Source of Truth
 *   29-38s  (870-1140)   \u00C9tape 3 : Monitoring continu
 *   38-45s  (1140-1350)  R\u00E9cap + CTA
 */

import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  interpolate,
  spring,
  useVideoConfig,
} from "remotion";
import { StarField } from "../sequences/01-StarField";
import { SectionTitle } from "../components/SectionTitle";
import { HologramBox } from "../components/HologramBox";
import { AnimatedList } from "../components/AnimatedList";
import { NeonText } from "../components/NeonText";

/* ─── Scene 1 : Accroche ─── */
const HookScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const items = ["3 \u00C9TAPES.", "24H.", "VOUS \u00CATES CIT\u00C9."];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 20,
      }}
    >
      {items.map((text, i) => {
        const delay = i * 25;
        const s = spring({
          frame: Math.max(0, frame - delay),
          fps,
          config: { damping: 12 },
        });

        return (
          <p
            key={i}
            style={{
              fontFamily: "Orbitron, sans-serif",
              fontSize: i === 2 ? 72 : 56,
              fontWeight: 900,
              color: i === 2 ? "#00FFFF" : "#fff",
              textShadow:
                i === 2 ? "0 0 40px rgba(0,255,255,0.5)" : "none",
              letterSpacing: 6,
              transform: `scale(${s})`,
            }}
          >
            {text}
          </p>
        );
      })}
    </AbsoluteFill>
  );
};

/* ─── Step Scene (generic) ─── */
interface StepSceneProps {
  stepNumber: number;
  title: string;
  subtitle: string;
  color: string;
  icon: string;
  details: { icon?: string; text: string }[];
  bottomText?: string;
}

const StepScene: React.FC<StepSceneProps> = ({
  stepNumber,
  title,
  subtitle,
  color,
  icon,
  details,
  bottomText,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const numberScale = spring({ frame, fps, config: { damping: 10 } });

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 60,
      }}
    >
      {/* Step number + icon */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 30,
          transform: `scale(${numberScale})`,
        }}
      >
        <div
          style={{
            width: 80,
            height: 80,
            borderRadius: "50%",
            border: `3px solid ${color}`,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "Orbitron, sans-serif",
            fontSize: 36,
            fontWeight: 900,
            color,
            boxShadow: `0 0 30px ${color}30`,
          }}
        >
          {stepNumber}
        </div>
        <span style={{ fontSize: 50 }}>{icon}</span>
      </div>

      <h2
        style={{
          fontFamily: "Orbitron, sans-serif",
          fontSize: 42,
          fontWeight: 700,
          color,
          letterSpacing: 4,
          marginTop: 25,
          textShadow: `0 0 20px ${color}40`,
        }}
      >
        {title}
      </h2>
      <p
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 22,
          color: "#888",
          marginTop: 8,
        }}
      >
        {subtitle}
      </p>

      {/* Details */}
      <div style={{ marginTop: 50, padding: "0 250px" }}>
        <HologramBox color={color} delay={25}>
          <div style={{ padding: "35px 45px" }}>
            <AnimatedList
              items={details}
              delay={35}
              color={color}
              fontSize={24}
            />
          </div>
        </HologramBox>
      </div>

      {bottomText && (
        <Sequence from={150}>
          <div
            style={{
              position: "absolute",
              bottom: 100,
              width: "100%",
              textAlign: "center",
            }}
          >
            <p
              style={{
                fontFamily: "Orbitron, sans-serif",
                fontSize: 24,
                color: `${color}90`,
                letterSpacing: 3,
                opacity: interpolate(frame - 150, [0, 20], [0, 1], {
                  extrapolateLeft: "clamp",
                  extrapolateRight: "clamp",
                }),
              }}
            >
              {bottomText}
            </p>
          </div>
        </Sequence>
      )}
    </AbsoluteFill>
  );
};

/* ─── Scene Recap + CTA ─── */
const RecapScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const steps = [
    { num: "1", label: "ANALYSER", color: "#00FFFF" },
    { num: "2", label: "G\u00C9N\u00C9RER", color: "#FFD700" },
    { num: "3", label: "MONITORER", color: "#4ECDC4" },
  ];

  const ctaScale = spring({
    frame: Math.max(0, frame - 60),
    fps,
    config: { damping: 12 },
  });

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 50,
      }}
    >
      {/* 3 steps recap */}
      <div style={{ display: "flex", gap: 60 }}>
        {steps.map((step, i) => {
          const delay = i * 15;
          const s = spring({
            frame: Math.max(0, frame - delay),
            fps,
            config: { damping: 14 },
          });

          return (
            <div
              key={i}
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 12,
                transform: `scale(${s})`,
              }}
            >
              <div
                style={{
                  width: 70,
                  height: 70,
                  borderRadius: "50%",
                  background: `${step.color}15`,
                  border: `2px solid ${step.color}`,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontFamily: "Orbitron",
                  fontSize: 30,
                  fontWeight: 900,
                  color: step.color,
                }}
              >
                {step.num}
              </div>
              <p
                style={{
                  fontFamily: "Orbitron, sans-serif",
                  fontSize: 20,
                  color: step.color,
                  letterSpacing: 3,
                }}
              >
                {step.label}
              </p>

              {/* Arrow between steps */}
              {i < 2 && (
                <div
                  style={{
                    position: "absolute",
                    left: `${33 + i * 33}%`,
                    top: "42%",
                    color: "#333",
                    fontSize: 30,
                  }}
                >
                  {"\u2192"}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* CTA */}
      <div style={{ transform: `scale(${ctaScale})` }}>
        <div
          style={{
            padding: "26px 70px",
            background: "linear-gradient(135deg, #7c3aed, #6d28d9)",
            borderRadius: 55,
            boxShadow: "0 0 40px rgba(124,58,237,0.4)",
          }}
        >
          <p
            style={{
              fontFamily: "Orbitron, sans-serif",
              fontSize: 28,
              fontWeight: "bold",
              color: "#fff",
              letterSpacing: 3,
            }}
          >
            COMMENCER MON AUDIT
          </p>
        </div>
      </div>

      <p
        style={{
          fontFamily: "Orbitron, sans-serif",
          fontSize: 24,
          color: "#FFD700",
          letterSpacing: 6,
          textShadow: "0 0 20px rgba(255,215,0,0.4)",
          opacity: interpolate(frame, [70, 95], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
        }}
      >
        CITEDBY.AI
      </p>
    </AbsoluteFill>
  );
};

/* ─── Main ─── */
export const HowItWorks: React.FC = () => {
  return (
    <AbsoluteFill style={{ backgroundColor: "#000" }}>
      <StarField />

      <Sequence from={0} durationInFrames={150} name="Hook">
        <HookScene />
      </Sequence>

      <Sequence from={150} durationInFrames={360} name="Etape 1">
        <StepScene
          stepNumber={1}
          title="ANALYSE DE PERCEPTION"
          subtitle="Notre scanner interroge les LLM"
          color="#00FFFF"
          icon={"\uD83D\uDD0D"}
          details={[
            { text: "Entrez votre URL ou nom de marque" },
            { text: "50 crit\u00E8res AEO analys\u00E9s en temps r\u00E9el" },
            { text: "Score de citabilit\u00E9 sur 100" },
            { text: "Benchmark E-E-A-T (Experience, Expertise, Autorit\u00E9, Confiance)" },
          ]}
          bottomText="R\u00C9SULTAT EN 30 SECONDES"
        />
      </Sequence>

      <Sequence from={510} durationInFrames={360} name="Etape 2">
        <StepScene
          stepNumber={2}
          title="SOURCE OF TRUTH"
          subtitle="G\u00E9n\u00E9rez votre r\u00E9f\u00E9rence canonique"
          color="#FFD700"
          icon={"\u2699\uFE0F"}
          details={[
            { text: "Schema.org JSON-LD g\u00E9n\u00E9r\u00E9 automatiquement" },
            { text: "llms.txt — guide de lecture pour les IA" },
            { text: "robots.txt — contr\u00F4le des crawlers IA" },
            { text: "Source of Truth — r\u00E9f\u00E9rence canonique LLM" },
          ]}
          bottomText="M\u00C9GA-G\u00C9N\u00C9RATION EN 1 CLIC"
        />
      </Sequence>

      <Sequence from={870} durationInFrames={270} name="Etape 3">
        <StepScene
          stepNumber={3}
          title="MONITORING CONTINU"
          subtitle="Suivez vos citations 24/7"
          color="#4ECDC4"
          icon={"\uD83D\uDCE1"}
          details={[
            { text: "Tracking sur ChatGPT, Claude, Gemini, Perplexity, AI Overviews" },
            { text: "Alertes en cas de baisse de visibilit\u00E9" },
            { text: "Analyse de sentiment et Share of Voice" },
            { text: "Rapports hebdomadaires automatiques" },
          ]}
        />
      </Sequence>

      <Sequence from={1140} durationInFrames={210} name="Recap + CTA">
        <RecapScene />
      </Sequence>
    </AbsoluteFill>
  );
};

