import { interpolate, spring, Easing } from "remotion";

// ── Brand Colors ──
export const COLORS = {
  bg: "#0a0a0f",
  bgCard: "#12121a",
  purple: "#a855f7",
  violet: "#7c3aed",
  rose: "#f43f5e",
  gold: "#f59e0b",
  green: "#10b981",
  cyan: "#06b6d4",
  white: "#ffffff",
  gray: "#9ca3af",
  grayDark: "#4b5563",
  grayLight: "#d1d5db",
};

// ── Gradients ──
export const GRADIENTS = {
  brand: "linear-gradient(135deg, #a855f7 0%, #7c3aed 50%, #6d28d9 100%)",
  brandWide: "linear-gradient(90deg, #a855f7, #7c3aed, #6d28d9)",
  dark: "linear-gradient(180deg, #0a0a0f 0%, #12121a 100%)",
  darkRadial: "radial-gradient(ellipse at center, #1a1030 0%, #0a0a0f 70%)",
  rose: "linear-gradient(135deg, #f43f5e 0%, #e11d48 100%)",
  gold: "linear-gradient(135deg, #f59e0b 0%, #d97706 100%)",
  glass: "linear-gradient(135deg, rgba(168,85,247,0.1) 0%, rgba(124,58,237,0.05) 100%)",
};

// ── Animation Helpers ──
export function fadeIn(frame: number, start: number, duration = 20) {
  return interpolate(frame, [start, start + duration], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
}

export function fadeOut(frame: number, start: number, duration = 15) {
  return interpolate(frame, [start, start + duration], [1, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
}

export function fadeInOut(frame: number, inStart: number, outStart: number, inDur = 20, outDur = 15) {
  const inVal = fadeIn(frame, inStart, inDur);
  const outVal = fadeOut(frame, outStart, outDur);
  return Math.min(inVal, outVal);
}

export function slideUp(frame: number, start: number, duration = 25) {
  return interpolate(frame, [start, start + duration], [60, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
}

export function slideDown(frame: number, start: number, duration = 25) {
  return interpolate(frame, [start, start + duration], [-40, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
}

export function slideLeft(frame: number, start: number, distance = 80, duration = 25) {
  return interpolate(frame, [start, start + duration], [distance, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
}

export function scaleSpring(frame: number, fps: number, delay = 0) {
  return spring({
    frame: frame - delay,
    fps,
    config: { damping: 12, stiffness: 120, mass: 0.8 },
  });
}

export function countUp(frame: number, start: number, end: number, target: number, duration = 30) {
  return Math.round(
    interpolate(frame, [start, start + duration], [0, target], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
      easing: Easing.out(Easing.cubic),
    })
  );
}

export function typewriter(text: string, frame: number, start: number, charsPerFrame = 0.8) {
  const elapsed = Math.max(0, frame - start);
  const chars = Math.floor(elapsed * charsPerFrame);
  return text.slice(0, chars);
}

export function pulseGlow(frame: number, speed = 0.05, min = 0.4, max = 1) {
  const t = (Math.sin(frame * speed) + 1) / 2;
  return min + t * (max - min);
}

// ── Style helpers ──
export function glassCard(opacity = 0.08): React.CSSProperties {
  return {
    background: `rgba(168, 85, 247, ${opacity})`,
    border: "1px solid rgba(168, 85, 247, 0.15)",
    borderRadius: 20,
    backdropFilter: "blur(20px)",
  };
}

export function gradientText(gradient = GRADIENTS.brand): React.CSSProperties {
  return {
    background: gradient,
    WebkitBackgroundClip: "text",
    WebkitTextFillColor: "transparent",
  };
}

import { AbsoluteFill, Sequence, useCurrentFrame } from "remotion";
import { Scene1_Hook } from "./scenes/Scene1_Hook";
import { Scene2_BrandReveal } from "./scenes/Scene2_BrandReveal";
import { Scene3_Features } from "./scenes/Scene3_Features";
import { Scene4_Stats } from "./scenes/Scene4_Stats";
import { Scene5_CTA } from "./scenes/Scene5_CTA";

/*
 * CitedBy.ai — Commercial Launch Video
 *
 * Storyboard (60s @ 30fps = 1800 frames):
 * ─────────────────────────────────────────
 * Scene 1 (0-8s)    : Hook — "Le SEO est mort"
 * Scene 2 (8-16s)   : Brand Reveal — CitedBy.ai + AI engines
 * Scene 3 (16-36s)  : Features — 3 Piliers + 15 outils
 * Scene 4 (36-46s)  : Dashboard — Monitoring temps reel
 * Scene 5 (46-54s)  : CTA — Audit gratuit
 *
 * Total: 54s = 1620 frames
 */

export const CommercialLaunch: React.FC = () => {
  return (
    <AbsoluteFill style={{ background: "#0a0a0f" }}>
      {/* Scene 1: Hook (frames 0-240, 8 seconds) */}
      <Sequence from={0} durationInFrames={240}>
        <Scene1_Hook />
      </Sequence>

      {/* Scene 2: Brand Reveal (frames 240-480, 8 seconds) */}
      <Sequence from={240} durationInFrames={240}>
        <Scene2_BrandReveal />
      </Sequence>

      {/* Scene 3: Features — 3 Pillars (frames 480-1080, 20 seconds) */}
      <Sequence from={480} durationInFrames={600}>
        <Scene3_Features />
      </Sequence>

      {/* Scene 4: Stats Dashboard (frames 1080-1380, 10 seconds) */}
      <Sequence from={1080} durationInFrames={300}>
        <Scene4_Stats />
      </Sequence>

      {/* Scene 5: CTA (frames 1380-1620, 8 seconds) */}
      <Sequence from={1380} durationInFrames={240}>
        <Scene5_CTA />
      </Sequence>
    </AbsoluteFill>
  );
};

