/**
 * Template 1: "Qu'est-ce que CitedBy.ai ?"
 * 45s (1350 frames @ 30fps) — Modern glass-morphism style
 *
 *   0-5s    (0-150)      Hook stat "50% des recherches via IA"
 *   5-17s   (150-510)    Brand + definition AEO
 *   17-27s  (510-810)    Les 4 super-pouvoirs
 *   27-37s  (810-1110)   Pour qui ?
 *   37-45s  (1110-1350)  CTA
 */

import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  useVideoConfig,
  Easing,
  interpolate,
