import {
  COLORS,
  GRADIENTS,
  fadeIn,
  slideUp,
  scaleSpring,
  countUp,
  pulseGlow,
  glassCard,
  gradientText,
  fadeInOut,
} from "../../animations";

/* ─── Background Grid (from CommercialLaunch) ─── */
const GridBg: React.FC = () => {
  const frame = useCurrentFrame();
  const dots: { x: number; y: number }[] = [];
  for (let row = 0; row < 14; row++) {
    for (let col = 0; col < 24; col++) {
      dots.push({ x: (col / 23) * 100, y: (row / 13) * 100 });
    }
  }
  return (
    <div style={{ position: "absolute", inset: 0, overflow: "hidden" }}>
      {dots.map((d, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            left: `${d.x}%`,
            top: `${d.y}%`,
            width: 3,
            height: 3,
            borderRadius: "50%",
            background: COLORS.purple,
            opacity: 0.06 + Math.sin(frame * 0.02 + i * 0.3) * 0.03,
          }}
        />
      ))}
    </div>
  );
};

/* ─── Glow ─── */
const AmbientGlow: React.FC<{ color?: string; size?: number }> = ({
  color = COLORS.purple,
  size = 700,
}) => {
  const frame = useCurrentFrame();
  return (
    <div
      style={{
        position: "absolute",
        left: "50%",
        top: "50%",
        width: size,
        height: size,
        transform: "translate(-50%, -50%)",
        borderRadius: "50%",
        background: `radial-gradient(circle, ${color}18 0%, transparent 70%)`,
        opacity: pulseGlow(frame, 0.04, 0.5, 0.8),
      }}
    />
  );
};

/* ═══ SCENE 1 : HOOK ═══ */
const HookScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const number = countUp(frame, 15, 0, 50, 40);
  const headOpacity = fadeIn(frame, 10, 20);
  const headY = slideUp(frame, 10, 25);
  const subOpacity = fadeIn(frame, 45, 20);
  const subY = slideUp(frame, 45, 25);
  const questionOpacity = fadeIn(frame, 80, 20);

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 30,
      }}
    >
      <AmbientGlow color={COLORS.rose} size={900} />

      <p
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 130,
          fontWeight: 800,
          ...gradientText("linear-gradient(135deg, #f59e0b 0%, #f43f5e 100%)"),
          opacity: headOpacity,
          transform: `translateY(${headY}px)`,
        }}
      >
        {number}%
      </p>

      <p
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 36,
          color: COLORS.grayLight,
          textAlign: "center",
          maxWidth: 800,
          lineHeight: 1.5,
          opacity: subOpacity,
          transform: `translateY(${subY}px)`,
        }}
      >
        des recherches passeront par l'IA d'ici 2026
      </p>

      <p
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 28,
          color: COLORS.rose,
          letterSpacing: 3,
          fontWeight: 600,
          marginTop: 15,
          opacity: questionOpacity,
        }}
      >
        VOTRE SITE SERA-T-IL VISIBLE ?
      </p>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 2 : BRAND + DEFINITION ═══ */
const BrandScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const logoScale = scaleSpring(frame, fps, 10);
  const tagOpacity = fadeIn(frame, 40, 20);
  const tagY = slideUp(frame, 40, 25);
  const cardOpacity = fadeIn(frame, 80, 25);
  const cardY = slideUp(frame, 80, 30);

  // AI engine chips
  const engines = [
    { name: "ChatGPT", color: "#10a37f" },
    { name: "Claude", color: "#d4a373" },
    { name: "Gemini", color: "#4285f4" },
    { name: "Perplexity", color: "#20b2aa" },
    { name: "AI Overviews", color: "#f43f5e" },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 35,
      }}
    >
      <AmbientGlow />

      {/* Logo */}
      <div style={{ transform: `scale(${logoScale})` }}>
        <span
          style={{
            fontFamily: "Inter, sans-serif",
            fontSize: 96,
            fontWeight: 800,
            letterSpacing: -2,
            ...gradientText(GRADIENTS.brand),
          }}
        >
          CitedBy
        </span>
        <span
          style={{
            fontFamily: "Inter, sans-serif",
            fontSize: 96,
            fontWeight: 300,
            color: COLORS.gold,
          }}
        >
          .ai
        </span>
      </div>

      {/* Tagline */}
      <p
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 26,
          fontWeight: 500,
          color: COLORS.gray,
          letterSpacing: 6,
          textTransform: "uppercase",
          opacity: tagOpacity,
          transform: `translateY(${tagY}px)`,
        }}
      >
        Answer Engine Optimization
      </p>

      {/* Engine chips */}
      <div
        style={{
          display: "flex",
          gap: 16,
          marginTop: 10,
          opacity: fadeIn(frame, 60, 20),
        }}
      >
        {engines.map((e, i) => {
          const chipScale = scaleSpring(frame, fps, 65 + i * 8);
          return (
            <div
              key={i}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 8,
                padding: "10px 20px",
                borderRadius: 30,
                border: `1px solid ${e.color}30`,
                background: `${e.color}08`,
                transform: `scale(${chipScale})`,
              }}
            >
              <div
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: "50%",
                  background: e.color,
                  boxShadow: `0 0 8px ${e.color}`,
                }}
              />
              <span style={{ fontSize: 16, color: e.color, fontWeight: 500 }}>
                {e.name}
              </span>
            </div>
          );
        })}
      </div>

      {/* Definition card */}
      <div
        style={{
          maxWidth: 950,
          marginTop: 15,
          opacity: cardOpacity,
          transform: `translateY(${cardY}px)`,
          ...glassCard(0.06),
          padding: "35px 50px",
        }}
      >
        <p
          style={{
            fontFamily: "Inter, sans-serif",
            fontSize: 24,
            color: COLORS.grayLight,
            lineHeight: 1.7,
            textAlign: "center",
          }}
        >
          La premi&egrave;re plateforme d'optimisation AEO/GEO qui analyse,
          g&eacute;n&egrave;re et monitore votre visibilit&eacute; dans les
          r&eacute;ponses des moteurs IA.
        </p>
      </div>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 3 : 4 SUPER-POUVOIRS ═══ */
const PowersScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const titleOpacity = fadeIn(frame, 10, 20);
  const titleY = slideUp(frame, 10, 25);

  const powers = [
    { icon: "\uD83D\uDD0D", title: "Analyser", desc: "50 crit\u00E8res AEO en temps r\u00E9el", color: COLORS.cyan },
    { icon: "\u26A1", title: "G\u00E9n\u00E9rer", desc: "15 outils d'optimisation IA", color: COLORS.gold },
    { icon: "\uD83D\uDCE1", title: "Monitorer", desc: "5 moteurs IA suivis 24/7", color: COLORS.green },
    { icon: "\uD83D\uDE80", title: "Convertir", desc: "3x plus de conversions", color: COLORS.rose },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 100,
      }}
    >
      <AmbientGlow />

      <h2
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 56,
          fontWeight: 700,
          opacity: titleOpacity,
          transform: `translateY(${titleY}px)`,
          ...gradientText(GRADIENTS.brand),
        }}
      >
        4 super-pouvoirs
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 30,
          marginTop: 70,
          padding: "0 200px",
          width: "100%",
        }}
      >
        {powers.map((p, i) => {
          const cardScale = scaleSpring(frame, fps, 50 + i * 18);
          return (
            <div
              key={i}
              style={{
                ...glassCard(0.05),
                padding: "35px 40px",
                display: "flex",
                alignItems: "center",
                gap: 24,
                transform: `scale(${cardScale})`,
                borderColor: `${p.color}20`,
              }}
            >
              <div
                style={{
                  width: 64,
                  height: 64,
                  borderRadius: 16,
                  background: `${p.color}12`,
                  border: `1px solid ${p.color}30`,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 32,
                  flexShrink: 0,
                }}
              >
                {p.icon}
              </div>
              <div>
                <p style={{ fontSize: 26, fontWeight: 700, color: p.color }}>
                  {p.title}
                </p>
                <p style={{ fontSize: 20, color: COLORS.gray, marginTop: 6 }}>
                  {p.desc}
                </p>
              </div>
            </div>
          );
        })}
      </div>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 4 : POUR QUI ? ═══ */
const AudienceScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const titleOpacity = fadeIn(frame, 10, 20);
  const titleY = slideUp(frame, 10, 25);

  const audiences = [
    { icon: "\uD83C\uDFE2", label: "Agences SEO", desc: "Proposez l'AEO \u00E0 vos clients", color: COLORS.purple },
    { icon: "\uD83D\uDED2", label: "E-Commerce", desc: "Produits cit\u00E9s par les IA", color: COLORS.cyan },
    { icon: "\uD83C\uDFAF", label: "Marques & SaaS", desc: "Visibilit\u00E9 dans les r\u00E9ponses", color: COLORS.gold },
    { icon: "\uD83D\uDCBB", label: "D\u00E9veloppeurs", desc: "API & int\u00E9grations SDK", color: COLORS.green },
