    >
      <AmbientGlow color={COLORS.violet} />

      <h2
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 56,
          fontWeight: 700,
          opacity: titleOpacity,
          transform: `translateY(${titleY}px)`,
          ...gradientText(GRADIENTS.brand),
        }}
      >
