      </h2>

      <div
        style={{
          display: "flex",
          gap: 40,
          marginTop: 80,
        }}
      >
        {audiences.map((a, i) => {
          const s = scaleSpring(frame, fps, 40 + i * 15);
          return (
            <div
              key={i}
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 16,
                width: 220,
                transform: `scale(${s})`,
              }}
            >
              <div
                style={{
                  width: 90,
                  height: 90,
                  borderRadius: "50%",
                  background: `${a.color}10`,
                  border: `2px solid ${a.color}30`,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 42,
                  boxShadow: `0 0 30px ${a.color}15`,
                }}
              >
                {a.icon}
              </div>
              <p style={{ fontSize: 22, fontWeight: 700, color: a.color }}>
                {a.label}
              </p>
              <p
                style={{
                  fontSize: 17,
                  color: COLORS.gray,
                  textAlign: "center",
                  lineHeight: 1.4,
                }}
              >
                {a.desc}
              </p>
            </div>
          );
        })}
      </div>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 5 : CTA ═══ */
const CtaScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const headOpacity = fadeIn(frame, 10, 20);
  const headY = slideUp(frame, 10, 25);
  const btnScale = scaleSpring(frame, fps, 40);
  const urlOpacity = fadeIn(frame, 70, 20);
  const glow = pulseGlow(frame, 0.04, 0.3, 0.6);

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 40,
      }}
    >
      <AmbientGlow />

      <p
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 52,
          fontWeight: 700,
          color: COLORS.white,
          opacity: headOpacity,
          transform: `translateY(${headY}px)`,
        }}
      >
        Pr&ecirc;t &agrave; &ecirc;tre cit&eacute; ?
      </p>

      <div
        style={{
          transform: `scale(${btnScale})`,
          padding: "22px 60px",
          borderRadius: 16,
          background: GRADIENTS.brand,
          boxShadow: `0 0 ${40 + glow * 40}px rgba(168,85,247,${0.3 + glow * 0.3})`,
          cursor: "pointer",
        }}
      >
        <p
          style={{
            fontFamily: "Inter, sans-serif",
            fontSize: 26,
            fontWeight: 700,
            color: COLORS.white,
            letterSpacing: 2,
          }}
        >
          PREMIER AUDIT GRATUIT
        </p>
      </div>

      <p
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: 28,
          fontWeight: 300,
          color: COLORS.gold,
          letterSpacing: 4,
          opacity: urlOpacity,
        }}
      >
        citedby.ai
      </p>
    </AbsoluteFill>
  );
};

/* ═══ MAIN ═══ */
export const WhatIsCitedBy: React.FC = () => {
  return (
    <AbsoluteFill style={{ background: GRADIENTS.darkRadial }}>
      <GridBg />

      <Sequence from={0} durationInFrames={150} name="Hook">
        <HookScene />
      </Sequence>
      <Sequence from={150} durationInFrames={360} name="Brand">
        <BrandScene />
      </Sequence>
      <Sequence from={510} durationInFrames={300} name="Powers">
        <PowersScene />
      </Sequence>
      <Sequence from={810} durationInFrames={300} name="Audience">
        <AudienceScene />
      </Sequence>
      <Sequence from={1110} durationInFrames={240} name="CTA">
        <CtaScene />
      </Sequence>
    </AbsoluteFill>
  );
};

