                  padding: "18px 30px",
                  fontSize: 20,
                  color: COLORS.gray,
                  fontWeight: 500,
                }}
              >
                {row.label}
              </div>
              <div
                style={{
                  padding: "18px 30px",
                  fontSize: 20,
                  color: `${COLORS.rose}cc`,
                  textAlign: "center",
                }}
              >
                {row.seo}
              </div>
              <div
                style={{
                  padding: "18px 30px",
                  fontSize: 20,
                  color: COLORS.purple,
                  textAlign: "center",
                  fontWeight: 500,
                }}
              >
                {row.aeo}
              </div>
            </div>
          );
        })}
      </div>
    </AbsoluteFill>
