};

/* ═══ SCENE 5: VERDICT + CTA ═══ */
const VerdictScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const h1 = fadeIn(frame, 10, 20);
  const h1Y = slideUp(frame, 10);
  const btnScale = scaleSpring(frame, fps, 50);
  const glow = pulseGlow(frame, 0.04, 0.3, 0.6);

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 40,
      }}
    >
      <Glow />

      <p
        style={{
          fontSize: 44,
          fontWeight: 700,
          color: COLORS.white,
          textAlign: "center",
          lineHeight: 1.5,
          maxWidth: 900,
          opacity: h1,
          transform: `translateY(${h1Y}px)`,
        }}
      >
        Le SEO ne suffit plus.
        <br />
        <span style={{ ...gradientText(GRADIENTS.brand) }}>
          L'AEO est le nouveau standard.
        </span>
      </p>

      <div
        style={{
          transform: `scale(${btnScale})`,
          padding: "22px 60px",
          borderRadius: 16,
          background: GRADIENTS.brand,
          boxShadow: `0 0 ${40 + glow * 40}px rgba(168,85,247,${0.3 + glow * 0.3})`,
        }}
      >
        <p style={{ fontSize: 26, fontWeight: 700, color: COLORS.white, letterSpacing: 2 }}>
          PASSEZ \u00C0 L'AEO
        </p>
      </div>

      <p
        style={{
          fontSize: 26,
          fontWeight: 300,
          color: COLORS.gold,
          letterSpacing: 4,
          opacity: fadeIn(frame, 80, 20),
        }}
      >
        citedby.ai
      </p>
    </AbsoluteFill>
  );
};

/* ═══ MAIN ═══ */
export const SeoVsAeo: React.FC = () => {
  return (
    <AbsoluteFill style={{ background: GRADIENTS.darkRadial }}>
      <GridBg />

      <Sequence from={0} durationInFrames={240} name="Hook">
        <HookScene />
      </Sequence>
      <Sequence from={240} durationInFrames={360} name="SEO">
        <SeoScene />
      </Sequence>
      <Sequence from={600} durationInFrames={360} name="AEO">
        <AeoScene />
      </Sequence>
      <Sequence from={960} durationInFrames={360} name="Comparatif">
        <ComparisonScene />
      </Sequence>
      <Sequence from={1320} durationInFrames={180} name="Verdict">
        <VerdictScene />
      </Sequence>
    </AbsoluteFill>
  );
};

