      <div
        style={{
          ...glassCard(0.05),
          marginTop: 50,
          padding: "40px 60px",
          maxWidth: 900,
          borderColor: `${COLORS.purple}25`,
        }}
      >
        {items.map((item, i) => {
          const delay = 50 + i * 18;
          const op = fadeIn(frame, delay, 15);
          const x = slideLeft(frame, delay, 40, 20);
          return (
            <div
              key={i}
