/* ═══ SCENE 4: SPLIT-SCREEN COMPARATIF ═══ */
const ComparisonScene: React.FC = () => {
  const frame = useCurrentFrame();

  const titleOpacity = fadeIn(frame, 5, 20);

  const rows = [
    { label: "Objectif", seo: "Ranking SERP", aeo: "Citation IA" },
    { label: "Cible", seo: "10 liens bleus", aeo: "R\u00E9ponse unique" },
    { label: "M\u00E9trique", seo: "Position + CTR", aeo: "Share of Voice IA" },
    { label: "Contenu", seo: "Long-format SEO", aeo: "Answer-First structur\u00E9" },
    { label: "Technique", seo: "Meta + backlinks", aeo: "Schema.org + llms.txt" },
    { label: "Signal", seo: "Backlinks", aeo: "Entity Authority + E-E-A-T" },
    { label: "Tendance", seo: "\u2198 En d\u00E9clin", aeo: "\u2197 En explosion" },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 60,
      }}
    >
      <h2
        style={{
          fontSize: 52,
          fontWeight: 700,
