                }}
              >
                {row.aeo}
              </div>
            </div>
          );
        })}
      </div>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 5: VERDICT + CTA ═══ */
const VerdictScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const h1 = fadeIn(frame, 10, 20);
  const h1Y = slideUp(frame, 10);
  const btnScale = scaleSpring(frame, fps, 50);
  const glow = pulseGlow(frame, 0.04, 0.3, 0.6);

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 40,
      }}
    >
      <Glow />

      <p
        style={{
          fontSize: 44,
          fontWeight: 700,
          color: COLORS.white,
          textAlign: "center",
          lineHeight: 1.5,
          maxWidth: 900,
          opacity: h1,
          transform: `translateY(${h1Y}px)`,
        }}
      >
        Le SEO ne suffit plus.
        <br />
        <span style={{ ...gradientText(GRADIENTS.brand) }}>
          L'AEO est le nouveau standard.
        </span>
      </p>

      <div
        style={{
          transform: `scale(${btnScale})`,
          padding: "22px 60px",
