/**
 * Template 2: "SEO vs AEO — Le Comparatif"
 * Duration: 50 seconds (1500 frames @ 30fps)
 *
 * Timeline:
 *   0-8s    (0-240)      Accroche : "Le SEO est-il mort ?"
 *   8-18s   (240-540)    Qu'est-ce que le SEO ? (rappel classique)
 *   18-28s  (540-840)    Qu'est-ce que l'AEO ? (nouveau paradigme)
 *   28-42s  (840-1260)   Tableau comparatif SEO vs AEO
 *   42-50s  (1260-1500)  Conclusion + CTA
 */

import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  interpolate,
  spring,
