/**
 * Template 3: "Les Outils G\u00E9n\u00E9ratifs CitedBy.ai"
 * Duration: 60 seconds (1800 frames @ 30fps)
 *
 * Timeline:
 *   0-5s    (0-150)      Accroche : "15 outils. 1 plateforme."
 *   5-15s   (150-450)    Cat\u00E9gorie 1 : Analyse & Audit (3 outils)
 *   15-25s  (450-750)    Cat\u00E9gorie 2 : G\u00E9n\u00E9ration de contenu (4 outils)
 *   25-35s  (750-1050)   Cat\u00E9gorie 3 : Fichiers techniques (4 outils)
 *   35-48s  (1050-1440)  Cat\u00E9gorie 4 : Monitoring & Tracking (4 outils)
 *   48-60s  (1440-1800)  M\u00E9ga-G\u00E9n\u00E9ration + CTA
 */

import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  interpolate,
  spring,
  useVideoConfig,
} from "remotion";
import { StarField } from "../sequences/01-StarField";
import { SectionTitle } from "../components/SectionTitle";
import { HologramBox } from "../components/HologramBox";

interface ToolCardProps {
  icon: string;
  name: string;
  desc: string;
  color: string;
  delay: number;
}

const ToolCard: React.FC<ToolCardProps> = ({ icon, name, desc, color, delay }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const scale = spring({
    frame: Math.max(0, frame - delay),
    fps,
    config: { damping: 14 },
  });

  return (
    <div style={{ transform: `scale(${scale})` }}>
      <HologramBox color={color} delay={delay}>
        <div
          style={{
            padding: "22px 28px",
            display: "flex",
            alignItems: "center",
            gap: 20,
            minWidth: 340,
          }}
        >
          <span style={{ fontSize: 40, flexShrink: 0 }}>{icon}</span>
          <div>
            <p
              style={{
                fontFamily: "Orbitron, sans-serif",
                fontSize: 20,
                color,
                fontWeight: 600,
              }}
            >
