/**
 * Template 4: "Pourquoi CitedBy.ai ?"
 * 50s (1500 frames @ 30fps)
 *
 *   0-8s    (0-240)      Chiffres alarmants
 *   8-22s   (240-660)    3 piliers de l'autorit\u00E9 IA
 *   22-34s  (660-1020)   10 cat\u00E9gories d'audit (score rings)
 *   34-44s  (1020-1320)  T\u00E9moignages
 *   44-50s  (1320-1500)  CTA
 */

import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  useVideoConfig,
  interpolate,
} from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  slideUp,
  slideLeft,
  scaleSpring,
  countUp,
  pulseGlow,
  glassCard,
  gradientText,
} from "../../animations";

/* ─── BG ─── */
const GridBg: React.FC = () => {
  const frame = useCurrentFrame();
  const dots: { x: number; y: number }[] = [];
  for (let r = 0; r < 12; r++)
    for (let c = 0; c < 22; c++)
      dots.push({ x: (c / 21) * 100, y: (r / 11) * 100 });
  return (
    <div style={{ position: "absolute", inset: 0 }}>
      {dots.map((d, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            left: `${d.x}%`,
            top: `${d.y}%`,
            width: 3,
            height: 3,
            borderRadius: "50%",
            background: COLORS.purple,
            opacity: 0.05 + Math.sin(frame * 0.02 + i * 0.35) * 0.03,
          }}
        />
      ))}
    </div>
  );
};

const Glow: React.FC<{ color?: string }> = ({ color = COLORS.purple }) => {
  const frame = useCurrentFrame();
  return (
    <div
      style={{
        position: "absolute",
        left: "50%",
        top: "50%",
        width: 800,
        height: 800,
        transform: "translate(-50%, -50%)",
        borderRadius: "50%",
        background: `radial-gradient(circle, ${color}15 0%, transparent 70%)`,
        opacity: pulseGlow(frame, 0.04, 0.5, 0.7),
      }}
    />
  );
};

/* ─── Score ring SVG ─── */
const ScoreRing: React.FC<{
  value: number;
  color: string;
  label: string;
  delay: number;
  size?: number;
}> = ({ value, color, label, delay, size = 120 }) => {
  const frame = useCurrentFrame();

  const progress = interpolate(frame - delay, [0, 40], [0, value / 100], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const op = fadeIn(frame, delay, 15);
  const r = (size - 12) / 2;
  const circ = 2 * Math.PI * r;

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 8,
        opacity: op,
      }}
    >
      <div style={{ position: "relative", width: size, height: size }}>
        <svg width={size} height={size} style={{ transform: "rotate(-90deg)" }}>
          <circle
            cx={size / 2}
            cy={size / 2}
            r={r}
            fill="none"
            stroke="rgba(255,255,255,0.04)"
            strokeWidth={6}
          />
          <circle
            cx={size / 2}
            cy={size / 2}
            r={r}
            fill="none"
            stroke={color}
            strokeWidth={6}
            strokeLinecap="round"
            strokeDasharray={circ}
            strokeDashoffset={circ * (1 - progress)}
            style={{ filter: `drop-shadow(0 0 6px ${color})` }}
          />
        </svg>
        <div
          style={{
            position: "absolute",
            inset: 0,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: size * 0.22,
            fontWeight: 800,
            color,
          }}
        >
          {Math.round(progress * 100)}
        </div>
      </div>
      <p style={{ fontSize: 14, color: COLORS.gray, textAlign: "center", maxWidth: size + 20 }}>
        {label}
      </p>
    </div>
  );
};

/* ═══ SCENE 1: CHIFFRES ═══ */
const StatsScene: React.FC = () => {
  const frame = useCurrentFrame();

  const stats = [
    { target: 40, prefix: "-", suffix: "%", label: "Clics organiques", color: COLORS.rose },
    { target: 65, prefix: "", suffix: "%", label: "Recherches sans clic", color: "#ff8c42" },
    { target: 50, prefix: "", suffix: "%", label: "Via IA d'ici 2026", color: COLORS.gold },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 40,
      }}
    >
      <Glow color={COLORS.rose} />

      <h2
        style={{
          fontSize: 52,
          fontWeight: 700,
          color: COLORS.rose,
          opacity: fadeIn(frame, 10, 20),
          transform: `translateY(${slideUp(frame, 10)}px)`,
        }}
      >
        Le constat
      </h2>

      <div style={{ display: "flex", gap: 80, marginTop: 20 }}>
        {stats.map((s, i) => {
          const delay = 30 + i * 18;
          const num = countUp(frame, delay, 0, s.target, 35);
          const op = fadeIn(frame, delay, 15);
          const sc = scaleSpring(frame, 30, delay);

          return (
            <div
              key={i}
              style={{
                textAlign: "center",
                opacity: op,
                transform: `scale(${sc})`,
              }}
            >
              <p
                style={{
                  fontSize: 80,
                  fontWeight: 800,
                  color: s.color,
                  textShadow: `0 0 30px ${s.color}40`,
                }}
              >
                {s.prefix}{num}{s.suffix}
              </p>
              <p style={{ fontSize: 22, color: COLORS.gray, marginTop: 8 }}>
                {s.label}
              </p>
            </div>
          );
        })}
      </div>

      <p
        style={{
          fontSize: 28,
          fontWeight: 500,
          color: COLORS.white,
          marginTop: 30,
          opacity: fadeIn(frame, 120, 20),
        }}
      >
        Les IA ne classent pas. Elles{" "}
        <span style={{ ...gradientText(GRADIENTS.brand), fontWeight: 700 }}>citent</span>.
      </p>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 2: 3 PILIERS ═══ */
const PillarsScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const pillars = [
    {
      icon: "\uD83C\uDF10",
      title: "Identit\u00E9",
      tag: "KNOWLEDGE GRAPH",
      desc: "Votre marque reconnue comme entit\u00E9 nomm\u00E9e",
      color: COLORS.cyan,
    },
    {
      icon: "\uD83E\uDDE0",
      title: "S\u00E9mantique",
      tag: "RAG-READY",
      desc: "Answer-First + JSON-LD pour l'ingestion IA",
      color: COLORS.gold,
    },
    {
      icon: "\uD83D\uDCE1",
      title: "Ubiquit\u00E9",
      tag: "SIGNAL",
      desc: "Annuaire + fichiers techniques + citations",
      color: COLORS.green,
    },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 80,
      }}
    >
      <Glow />

      <h2
        style={{
          fontSize: 48,
          fontWeight: 700,
          ...gradientText(GRADIENTS.brand),
          opacity: fadeIn(frame, 10, 20),
          transform: `translateY(${slideUp(frame, 10)}px)`,
        }}
      >
        3 piliers de l'autorit\u00E9 IA
      </h2>

      <div style={{ display: "flex", gap: 40, marginTop: 70, padding: "0 120px" }}>
        {pillars.map((p, i) => {
          const s = scaleSpring(frame, fps, 40 + i * 20);
          return (
            <div
              key={i}
              style={{
                ...glassCard(0.05),
                padding: "45px 35px",
                textAlign: "center",
                flex: 1,
                transform: `scale(${s})`,
                borderColor: `${p.color}20`,
              }}
            >
              {/* Top accent */}
              <div
                style={{
                  position: "absolute",
                  top: 0,
                  left: "20%",
                  right: "20%",
                  height: 3,
                  background: p.color,
                  borderRadius: "0 0 2px 2px",
                }}
              />

              <span style={{ fontSize: 50 }}>{p.icon}</span>
              <p style={{ fontSize: 28, fontWeight: 700, color: p.color, marginTop: 20 }}>
                {p.title}
              </p>
              <p
                style={{
                  fontSize: 14,
                  color: `${p.color}80`,
                  letterSpacing: 3,
                  marginTop: 6,
                  fontWeight: 500,
                }}
              >
                {p.tag}
              </p>
              <p style={{ fontSize: 20, color: COLORS.gray, marginTop: 18, lineHeight: 1.5 }}>
                {p.desc}
              </p>
            </div>
          );
        })}
      </div>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 3: 10 CATEGORIES ═══ */
const CategoriesScene: React.FC = () => {
  const frame = useCurrentFrame();

  const cats = [
    { name: "Infrastructure", score: 90, color: COLORS.cyan },
    { name: "S\u00E9mantique", score: 85, color: "#3b82f6" },
    { name: "Contenu", score: 78, color: COLORS.gold },
    { name: "Autorit\u00E9", score: 82, color: COLORS.purple },
    { name: "Donn\u00E9es", score: 70, color: COLORS.green },
    { name: "GEO", score: 75, color: COLORS.rose },
    { name: "Confiance", score: 88, color: "#10b981" },
    { name: "Fra\u00EEcheur", score: 65, color: "#ff8c42" },
    { name: "M\u00E9dia", score: 60, color: "#8b5cf6" },
    { name: "UX", score: 92, color: COLORS.cyan },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 50,
      }}
    >
      <h2
        style={{
          fontSize: 44,
          fontWeight: 700,
          ...gradientText(GRADIENTS.brand),
          opacity: fadeIn(frame, 5, 20),
        }}
      >
        50 crit\u00E8res — 10 cat\u00E9gories
      </h2>
      <p
        style={{
          fontSize: 20,
          color: COLORS.grayDark,
          marginTop: 8,
          opacity: fadeIn(frame, 15, 15),
        }}
      >
        L'audit AEO le plus complet du march\u00E9
      </p>

      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          justifyContent: "center",
          gap: 28,
          marginTop: 40,
          padding: "0 140px",
        }}
      >
        {cats.map((c, i) => (
          <ScoreRing
            key={i}
            value={c.score}
            color={c.color}
            label={c.name}
            delay={20 + i * 7}
            size={130}
          />
        ))}
      </div>
    </AbsoluteFill>
  );
};

/* ═══ SCENE 4: TEMOIGNAGES ═══ */
const TestimonialsScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const testimonials = [
    {
      quote: "De 0 citation \u00E0 recommand\u00E9 par ChatGPT en 3 semaines",
      name: "Marie Dubois",
      role: "CMO, TechFlow SaaS",
      color: COLORS.green,
    },
    {
      quote: "Schema.org et Source of Truth ont transform\u00E9 notre pr\u00E9sence IA",
      name: "Thomas Martin",
      role: "Head of SEO, GreenGarden",
      color: COLORS.gold,
    },
    {
      quote: "Le monitoring est une mine d'or pour notre strat\u00E9gie",
      name: "Sophie Laurent",
      role: "Dir. Digitale, OmniMedia",
      color: COLORS.purple,
    },
  ];

  const badges = ["RGPD", "SSL", "99.9% Uptime", "Made in France"];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 80,
      }}
    >
      <Glow color={COLORS.gold} />

      <h2
        style={{
          fontSize: 44,
          fontWeight: 700,
          color: COLORS.gold,
          opacity: fadeIn(frame, 10, 20),
          transform: `translateY(${slideUp(frame, 10)}px)`,
        }}
      >
        Ils nous font confiance
      </h2>

      <div style={{ display: "flex", gap: 30, marginTop: 60, padding: "0 100px" }}>
        {testimonials.map((t, i) => {
          const s = scaleSpring(frame, fps, 30 + i * 22);
          return (
            <div
              key={i}
              style={{
                ...glassCard(0.05),
                padding: "35px 30px",
                flex: 1,
                transform: `scale(${s})`,
                borderColor: `${t.color}20`,
              }}
            >
              <p
                style={{
                  fontSize: 21,
                  color: COLORS.grayLight,
                  fontStyle: "italic",
                  lineHeight: 1.6,
                  marginBottom: 24,
                }}
              >
                \u00AB {t.quote} \u00BB
              </p>
              <p style={{ fontSize: 17, fontWeight: 600, color: t.color }}>{t.name}</p>
              <p style={{ fontSize: 14, color: COLORS.grayDark, marginTop: 4 }}>{t.role}</p>
            </div>
          );
        })}
      </div>

      {/* Trust badges */}
      <div
        style={{
          display: "flex",
          gap: 30,
          marginTop: 50,
          opacity: fadeIn(frame, 120, 20),
        }}
      >
        {badges.map((b, i) => (
          <span
            key={i}
            style={{
              fontSize: 14,
              color: COLORS.grayDark,
              letterSpacing: 2,
              padding: "8px 18px",
