            </HologramBox>
          </Sequence>
        ))}
      </div>

      {/* Trust badges */}
      <Sequence from={100}>
        <div
          style={{
            position: "absolute",
            bottom: 100,
            display: "flex",
            gap: 50,
            opacity: interpolate(0, [0, 1], [0.6, 0.6]),
          }}
        >
          {["RGPD", "SSL", "99.9% Uptime", "Made in France"].map((badge, i) => (
            <span
              key={i}
              style={{
                fontFamily: "Orbitron, sans-serif",
                fontSize: 14,
                color: "#555",
                letterSpacing: 2,
                padding: "8px 16px",
                border: "1px solid #333",
                borderRadius: 20,
              }}
            >
              {badge}
            </span>
          ))}
        </div>
      </Sequence>
    </AbsoluteFill>
  );
};

/* ─── Scene 5 : CTA ─── */
const CtaScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const scale = spring({ frame, fps, config: { damping: 12 } });
  const pulse = 1 + Math.sin(frame * 0.12) * 0.04;

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 40,
      }}
    >
      <NeonText
        text="REJOIGNEZ L'\u00C8RE AEO"
        color="#00FFFF"
        fontSize={48}
        delay={0}
      />

      <div style={{ transform: `scale(${scale * pulse})`, marginTop: 20 }}>
        <div
          style={{
            padding: "28px 70px",
            background: "linear-gradient(135deg, #00FFFF, #0080FF)",
            borderRadius: 60,
            boxShadow: "0 0 50px rgba(0,255,255,0.4)",
          }}
        >
          <p
            style={{
              fontFamily: "Orbitron, sans-serif",
              fontSize: 30,
              fontWeight: "bold",
              color: "#000",
              letterSpacing: 3,
            }}
          >
            AUDIT GRATUIT EN 30 SECONDES
          </p>
        </div>
      </div>

      <p
        style={{
          fontFamily: "Orbitron, sans-serif",
          fontSize: 26,
          color: "#FFD700",
          letterSpacing: 6,
          marginTop: 20,
          textShadow: "0 0 20px rgba(255,215,0,0.4)",
          opacity: interpolate(frame, [40, 65], [0, 1], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
        }}
      >
        CITEDBY.AI
      </p>
    </AbsoluteFill>
  );
};

/* ─── Main ─── */
export const WhyCitedBy: React.FC = () => {
  return (
    <AbsoluteFill style={{ backgroundColor: "#000" }}>
      <StarField />

      <Sequence from={0} durationInFrames={240} name="Constat">
        <ConstatScene />
      </Sequence>

      <Sequence from={240} durationInFrames={360} name="3 Piliers">
        <PillarsScene />
      </Sequence>

      <Sequence from={600} durationInFrames={360} name="10 Categories">
        <CategoriesScene />
      </Sequence>

      <Sequence from={960} durationInFrames={300} name="Temoignages">
        <TestimonialsScene />
      </Sequence>

      <Sequence from={1260} durationInFrames={240} name="CTA">
        <CtaScene />
      </Sequence>
    </AbsoluteFill>
  );
};

