/**
 * Template 5: "Comment \u00E7a marche ?"
 * 45s (1350 frames @ 30fps)
 *
 *   0-5s    (0-150)      "3 \u00E9tapes. 24h. Cit\u00E9."
 *   5-17s   (150-510)    \u00C9tape 1 : Analyse de perception
 *   17-29s  (510-870)    \u00C9tape 2 : G\u00E9n\u00E9ration Source of Truth
 *   29-38s  (870-1140)   \u00C9tape 3 : Monitoring continu
 *   38-45s  (1140-1350)  R\u00E9cap + CTA
 */

import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  useVideoConfig,
  interpolate,
} from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  slideUp,
  slideLeft,
  scaleSpring,
  pulseGlow,
  glassCard,
  gradientText,
} from "../../animations";

/* ─── BG ─── */
const GridBg: React.FC = () => {
  const frame = useCurrentFrame();
  const dots: { x: number; y: number }[] = [];
  for (let r = 0; r < 12; r++)
    for (let c = 0; c < 22; c++)
      dots.push({ x: (c / 21) * 100, y: (r / 11) * 100 });
  return (
    <div style={{ position: "absolute", inset: 0 }}>
      {dots.map((d, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            left: `${d.x}%`,
            top: `${d.y}%`,
            width: 3,
            height: 3,
            borderRadius: "50%",
            background: COLORS.purple,
            opacity: 0.05 + Math.sin(frame * 0.02 + i * 0.35) * 0.03,
          }}
        />
      ))}
    </div>
  );
};

const Glow: React.FC<{ color?: string }> = ({ color = COLORS.purple }) => {
  const frame = useCurrentFrame();
  return (
    <div
      style={{
        position: "absolute",
        left: "50%",
        top: "50%",
        width: 800,
        height: 800,
        transform: "translate(-50%, -50%)",
        borderRadius: "50%",
        background: `radial-gradient(circle, ${color}15 0%, transparent 70%)`,
        opacity: pulseGlow(frame, 0.04, 0.5, 0.7),
      }}
    />
  );
};

/* ═══ SCENE 1: HOOK ═══ */
const HookScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const lines = [
    { text: "3 \u00E9tapes.", delay: 0, size: 60, color: COLORS.white },
    { text: "24 heures.", delay: 20, size: 60, color: COLORS.gold },
    { text: "Vous \u00EAtes cit\u00E9.", delay: 45, size: 72, gradient: true },
  ];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 20,
      }}
    >
      <Glow />

      {lines.map((l, i) => {
        const s = scaleSpring(frame, fps, l.delay);
        return (
          <p
            key={i}
            style={{
              fontFamily: "Inter, sans-serif",
              fontSize: l.size,
              fontWeight: 800,
              transform: `scale(${s})`,
              ...(l.gradient
                ? gradientText(GRADIENTS.brand)
                : { color: l.color }),
            }}
          >
            {l.text}
          </p>
        );
      })}
    </AbsoluteFill>
  );
};

/* ═══ STEP SCENE (generic) ═══ */
interface StepProps {
  number: number;
  title: string;
  subtitle: string;
  color: string;
  icon: string;
  items: string[];
  badge?: string;
}

const StepScene: React.FC<StepProps> = ({
  number,
  title,
  subtitle,
  color,
  icon,
  items,
  badge,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const numScale = scaleSpring(frame, fps, 5);

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 60,
      }}
    >
      <Glow color={color} />

      {/* Step number + icon row */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 24,
          transform: `scale(${numScale})`,
        }}
      >
        <div
          style={{
            width: 70,
            height: 70,
            borderRadius: "50%",
            border: `3px solid ${color}`,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 32,
            fontWeight: 800,
            color,
            boxShadow: `0 0 25px ${color}25`,
          }}
        >
          {number}
        </div>
        <span style={{ fontSize: 44 }}>{icon}</span>
      </div>

      {/* Title */}
      <div
        style={{
          marginTop: 20,
          textAlign: "center",
          opacity: fadeIn(frame, 15, 18),
          transform: `translateY(${slideUp(frame, 15)}px)`,
        }}
      >
        <h2 style={{ fontSize: 44, fontWeight: 700, color }}>{title}</h2>
        <p style={{ fontSize: 20, color: COLORS.grayDark, marginTop: 6 }}>{subtitle}</p>
      </div>

      {/* Detail card */}
      <div
        style={{
          ...glassCard(0.05),
          marginTop: 40,
          padding: "35px 50px",
          maxWidth: 950,
          borderColor: `${color}20`,
          opacity: fadeIn(frame, 35, 20),
          transform: `translateY(${slideUp(frame, 35, 20)}px)`,
        }}
      >
        {items.map((item, i) => {
          const d = 50 + i * 14;
          return (
            <div
              key={i}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 14,
                marginBottom: 18,
                opacity: fadeIn(frame, d, 12),
                transform: `translateX(${slideLeft(frame, d, 30, 15)}px)`,
              }}
            >
              <div
                style={{
                  width: 7,
                  height: 7,
                  borderRadius: "50%",
                  background: color,
                  flexShrink: 0,
                }}
              />
              <p style={{ fontSize: 24, color: COLORS.grayLight }}>{item}</p>
            </div>
          );
        })}
      </div>

      {/* Badge */}
      {badge && (
        <div
          style={{
            marginTop: 30,
            padding: "14px 35px",
            borderRadius: 12,
            background: `${color}10`,
            border: `1px solid ${color}25`,
            opacity: fadeIn(frame, 140, 20),
          }}
        >
          <p style={{ fontSize: 20, fontWeight: 600, color, letterSpacing: 2 }}>
            {badge}
          </p>
        </div>
      )}
    </AbsoluteFill>
  );
};

/* ═══ SCENE 5: RECAP + CTA ═══ */
const RecapScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const steps = [
    { num: "1", label: "Analyser", color: COLORS.cyan },
    { num: "2", label: "G\u00E9n\u00E9rer", color: COLORS.gold },
    { num: "3", label: "Monitorer", color: COLORS.green },
  ];

  const btnScale = scaleSpring(frame, fps, 70);
  const glow = pulseGlow(frame, 0.04, 0.3, 0.6);

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 50,
      }}
    >
      <Glow />

      {/* Step circles row */}
      <div style={{ display: "flex", alignItems: "center", gap: 30 }}>
        {steps.map((step, i) => {
          const s = scaleSpring(frame, fps, 5 + i * 12);
          return (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 30 }}>
              <div
                style={{
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  gap: 10,
                  transform: `scale(${s})`,
                }}
              >
                <div
                  style={{
                    width: 64,
                    height: 64,
                    borderRadius: "50%",
                    background: `${step.color}10`,
                    border: `2px solid ${step.color}50`,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    fontSize: 28,
                    fontWeight: 800,
                    color: step.color,
                  }}
                >
                  {step.num}
                </div>
                <p style={{ fontSize: 18, fontWeight: 600, color: step.color, letterSpacing: 1 }}>
                  {step.label}
                </p>
              </div>

              {/* Arrow between */}
              {i < 2 && (
                <span style={{ fontSize: 24, color: COLORS.grayDark, opacity: fadeIn(frame, 20 + i * 12, 12) }}>
                  {"\u2192"}
                </span>
              )}
            </div>
          );
        })}
      </div>

      {/* CTA */}
      <div
        style={{
          transform: `scale(${btnScale})`,
          padding: "22px 60px",
          borderRadius: 16,
          background: GRADIENTS.brand,
          boxShadow: `0 0 ${40 + glow * 40}px rgba(168,85,247,${0.3 + glow * 0.3})`,
        }}
      >
        <p style={{ fontSize: 26, fontWeight: 700, color: COLORS.white, letterSpacing: 2 }}>
          COMMENCER MON AUDIT
        </p>
      </div>

      <p
        style={{
          fontSize: 26,
          fontWeight: 300,
          color: COLORS.gold,
          letterSpacing: 4,
          opacity: fadeIn(frame, 90, 20),
        }}
      >
        citedby.ai
      </p>
    </AbsoluteFill>
  );
};

/* ═══ MAIN ═══ */
export const HowItWorks: React.FC = () => {
  return (
    <AbsoluteFill style={{ background: GRADIENTS.darkRadial }}>
      <GridBg />

      <Sequence from={0} durationInFrames={150} name="Hook">
        <HookScene />
      </Sequence>

      <Sequence from={150} durationInFrames={360} name="Etape 1">
        <StepScene
          number={1}
          title="Analyse de perception"
          subtitle="Notre scanner interroge les LLM"
          color={COLORS.cyan}
          icon={"\uD83D\uDD0D"}
          items={[
            "Entrez votre URL ou nom de marque",
            "50 crit\u00E8res AEO analys\u00E9s en temps r\u00E9el",
            "Score de citabilit\u00E9 sur 100",
            "Benchmark E-E-A-T complet",
          ]}
          badge="R\u00C9SULTAT EN 30 SECONDES"
        />
      </Sequence>

      <Sequence from={510} durationInFrames={360} name="Etape 2">
        <StepScene
          number={2}
          title="Source of Truth"
          subtitle="G\u00E9n\u00E9rez votre r\u00E9f\u00E9rence canonique"
          color={COLORS.gold}
          icon={"\u2699\uFE0F"}
          items={[
            "Schema.org JSON-LD g\u00E9n\u00E9r\u00E9 automatiquement",
            "llms.txt \u2014 guide de lecture pour les IA",
            "robots.txt \u2014 contr\u00F4le des crawlers IA",
            "Source of Truth \u2014 r\u00E9f\u00E9rence canonique LLM",
          ]}
          badge="M\u00C9GA-G\u00C9N\u00C9RATION EN 1 CLIC"
        />
      </Sequence>

      <Sequence from={870} durationInFrames={270} name="Etape 3">
        <StepScene
          number={3}
          title="Monitoring continu"
          subtitle="Suivez vos citations 24/7"
          color={COLORS.green}
          icon={"\uD83D\uDCE1"}
          items={[
            "ChatGPT, Claude, Gemini, Perplexity, AI Overviews",
            "Alertes en cas de baisse de visibilit\u00E9",
            "Analyse de sentiment et Share of Voice",
            "Rapports hebdomadaires automatiques",
          ]}
        />
      </Sequence>

      <Sequence from={1140} durationInFrames={210} name="Recap">
        <RecapScene />
      </Sequence>
    </AbsoluteFill>
  );
};

