            alignItems: "center",
            justifyContent: "center",
            fontSize: 32,
            fontWeight: 800,
            color,
            boxShadow: `0 0 25px ${color}25`,
          }}
        >
          {number}
        </div>
        <span style={{ fontSize: 44 }}>{icon}</span>
      </div>

      {/* Title */}
      <div
        style={{
          marginTop: 20,
          textAlign: "center",
          opacity: fadeIn(frame, 15, 18),
          transform: `translateY(${slideUp(frame, 15)}px)`,
        }}
      >
        <h2 style={{ fontSize: 44, fontWeight: 700, color }}>{title}</h2>
        <p style={{ fontSize: 20, color: COLORS.grayDark, marginTop: 6 }}>{subtitle}</p>
      </div>

      {/* Detail card */}
      <div
        style={{
          ...glassCard(0.05),
          marginTop: 40,
          padding: "35px 50px",
          maxWidth: 950,
          borderColor: `${color}20`,
          opacity: fadeIn(frame, 35, 20),
          transform: `translateY(${slideUp(frame, 35, 20)}px)`,
        }}
      >
        {items.map((item, i) => {
          const d = 50 + i * 14;
          return (
            <div
              key={i}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 14,
                marginBottom: 18,
                opacity: fadeIn(frame, d, 12),
                transform: `translateX(${slideLeft(frame, d, 30, 15)}px)`,
              }}
            >
              <div
                style={{
                  width: 7,
                  height: 7,
                  borderRadius: "50%",
                  background: color,
                  flexShrink: 0,
                }}
              />
              <p style={{ fontSize: 24, color: COLORS.grayLight }}>{item}</p>
            </div>
          );
        })}
      </div>

      {/* Badge */}
      {badge && (
        <div
          style={{
            marginTop: 30,
            padding: "14px 35px",
            borderRadius: 12,
            background: `${color}10`,
            border: `1px solid ${color}25`,
            opacity: fadeIn(frame, 140, 20),
          }}
        >
          <p style={{ fontSize: 20, fontWeight: 600, color, letterSpacing: 2 }}>
            {badge}
          </p>
        </div>
      )}
    </AbsoluteFill>
  );
};

/* ═══ SCENE 5: RECAP + CTA ═══ */
const RecapScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const steps = [
    { num: "1", label: "Analyser", color: COLORS.cyan },
