    >
      <Glow />

      {/* Step circles row */}
      <div style={{ display: "flex", alignItems: "center", gap: 30 }}>
        {steps.map((step, i) => {
          const s = scaleSpring(frame, fps, 5 + i * 12);
          return (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 30 }}>
              <div
                style={{
                  display: "flex",
