                    color: step.color,
                  }}
                >
                  {step.num}
                </div>
                <p style={{ fontSize: 18, fontWeight: 600, color: step.color, letterSpacing: 1 }}>
                  {step.label}
                </p>
              </div>

              {/* Arrow between */}
              {i < 2 && (
                <span style={{ fontSize: 24, color: COLORS.grayDark, opacity: fadeIn(frame, 20 + i * 12, 12) }}>
                  {"\u2192"}
                </span>
              )}
            </div>
          );
        })}
      </div>

      {/* CTA */}
      <div
        style={{
          transform: `scale(${btnScale})`,
          padding: "22px 60px",
          borderRadius: 16,
