import { Composition } from "remotion";
import { HelloWorld } from "./HelloWorld";
import { CommercialLaunch } from "./CommercialLaunch";
import { CitedByPromoVideo } from "./src/Video";
import { WhatIsCitedBy } from "./src/templates/WhatIsCitedBy";
import { SeoVsAeo } from "./src/templates/SeoVsAeo";
import { GenerativeToolsDemo } from "./src/templates/GenerativeToolsDemo";
import { WhyCitedBy } from "./src/templates/WhyCitedBy";
import { HowItWorks } from "./src/templates/HowItWorks";
import "./src/styles/global.css";

export const RemotionRoot: React.FC = () => {
  return (
    <>
      {/* ═══ TEMPLATES PEDAGOGIQUES ═══ */}

      {/* Template 1: Qu'est-ce que CitedBy.ai ? — 45s */}
      <Composition
        id="WhatIsCitedBy"
        component={WhatIsCitedBy}
        durationInFrames={1350}
        fps={30}
        width={1920}
        height={1080}
      />

      {/* Template 2: SEO vs AEO — 50s */}
      <Composition
        id="SeoVsAeo"
        component={SeoVsAeo}
        durationInFrames={1500}
        fps={30}
        width={1920}
        height={1080}
      />

      {/* Template 3: Les Outils Generatifs — 60s */}
      <Composition
        id="GenerativeToolsDemo"
        component={GenerativeToolsDemo}
        durationInFrames={1800}
        fps={30}
        width={1920}
        height={1080}
      />

      {/* Template 4: Pourquoi CitedBy.ai ? — 50s */}
      <Composition
        id="WhyCitedBy"
        component={WhyCitedBy}
        durationInFrames={1500}
        fps={30}
        width={1920}
        height={1080}
      />

      {/* Template 5: Comment ca marche ? — 45s */}
      <Composition
        id="HowItWorks"
        component={HowItWorks}
        durationInFrames={1350}
        fps={30}
        width={1920}
        height={1080}
      />

      {/* ═══ PROMO STAR WARS ═══ */}

      <Composition
        id="CitedByPromo"
        component={CitedByPromoVideo}
        durationInFrames={60 * 30}
        fps={30}
        width={1920}
        height={1080}
      />

      <Composition
        id="CitedByPromoShort"
        component={CitedByPromoVideo}
        durationInFrames={30 * 30}
        fps={30}
        width={1080}
        height={1080}
      />

      {/* ═══ EXISTANTS ═══ */}

      <Composition
        id="CommercialLaunch"
        component={CommercialLaunch}
        durationInFrames={1620}
        fps={30}
        width={1920}
        height={1080}
      />
      <Composition
        id="HelloWorld"
        component={HelloWorld}
        durationInFrames={150}
        fps={30}
        width={1920}
        height={1080}
      />
    </>
  );
};

