/**
 * Template 3: "Les 15 Outils G\u00E9n\u00E9ratifs"
 * 60s (1800 frames @ 30fps)
 *
 *   0-5s    (0-150)      "15 outils. 1 plateforme."
 *   5-17s   (150-510)    Analyse & Audit (3 outils)
 *   17-29s  (510-870)    Contenu (4 outils)
 *   29-41s  (870-1230)   Technique (4 outils)
 *   41-52s  (1230-1560)  Monitoring (4 outils)
 *   52-60s  (1560-1800)  M\u00E9ga-G\u00E9n\u00E9ration + CTA
 */

import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  slideUp,
  slideLeft,
  scaleSpring,
  countUp,
  pulseGlow,
  glassCard,
  gradientText,
} from "../../animations";

/* ─── BG ─── */
const GridBg: React.FC = () => {
  const frame = useCurrentFrame();
  const dots: { x: number; y: number }[] = [];
  for (let r = 0; r < 12; r++)
    for (let c = 0; c < 22; c++)
      dots.push({ x: (c / 21) * 100, y: (r / 11) * 100 });
  return (
    <div style={{ position: "absolute", inset: 0 }}>
      {dots.map((d, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            left: `${d.x}%`,
            top: `${d.y}%`,
            width: 3,
            height: 3,
            borderRadius: "50%",
            background: COLORS.purple,
            opacity: 0.05 + Math.sin(frame * 0.018 + i * 0.35) * 0.03,
          }}
        />
      ))}
    </div>
  );
};

const Glow: React.FC<{ color?: string }> = ({ color = COLORS.purple }) => {
  const frame = useCurrentFrame();
  return (
    <div
      style={{
        position: "absolute",
        left: "50%",
        top: "50%",
        width: 800,
        height: 800,
        transform: "translate(-50%, -50%)",
        borderRadius: "50%",
        background: `radial-gradient(circle, ${color}15 0%, transparent 70%)`,
        opacity: pulseGlow(frame, 0.04, 0.4, 0.7),
      }}
    />
  );
};

/* ─── Tool card ─── */
interface ToolProps {
  icon: string;
  name: string;
  desc: string;
  color: string;
  index: number;
  baseDelay: number;
}
const ToolCard: React.FC<ToolProps> = ({ icon, name, desc, color, index, baseDelay }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const delay = baseDelay + index * 20;
  const s = scaleSpring(frame, fps, delay);

  return (
    <div
      style={{
        ...glassCard(0.05),
        padding: "28px 32px",
        display: "flex",
        alignItems: "center",
        gap: 20,
        minWidth: 380,
        transform: `scale(${s})`,
        borderColor: `${color}20`,
      }}
    >
      <div
        style={{
          width: 52,
          height: 52,
          borderRadius: 14,
          background: `${color}12`,
          border: `1px solid ${color}25`,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: 26,
          flexShrink: 0,
        }}
      >
        {icon}
      </div>
      <div>
        <p style={{ fontSize: 22, fontWeight: 700, color }}>{name}</p>
        <p style={{ fontSize: 17, color: COLORS.gray, marginTop: 4 }}>{desc}</p>
      </div>
    </div>
  );
};

/* ═══ HOOK ═══ */
const HookScene: React.FC = () => {
  const frame = useCurrentFrame();
  const num = countUp(frame, 15, 0, 15, 35);

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 25,
      }}
    >
      <Glow color={COLORS.gold} />
      <p
        style={{
          fontSize: 120,
          fontWeight: 800,
          ...gradientText("linear-gradient(135deg, #f59e0b, #a855f7)"),
          opacity: fadeIn(frame, 10, 20),
        }}
      >
        {num}
      </p>
      <p
        style={{
          fontSize: 44,
          fontWeight: 700,
          color: COLORS.white,
          letterSpacing: 2,
          opacity: fadeIn(frame, 35, 20),
        }}
      >
        outils. <span style={{ color: COLORS.gold }}>1</span> plateforme.
      </p>
      <p
        style={{
          fontSize: 24,
          color: COLORS.gray,
          opacity: fadeIn(frame, 60, 20),
        }}
      >
        Tout pour \u00EAtre cit\u00E9 par les IA
      </p>
    </AbsoluteFill>
  );
};

/* ═══ CATEGORY SCENE (generic) ═══ */
interface CatProps {
  title: string;
  subtitle: string;
  color: string;
  tools: { icon: string; name: string; desc: string }[];
}
const CategoryScene: React.FC<CatProps> = ({ title, subtitle, color, tools }) => {
  const frame = useCurrentFrame();

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 80,
      }}
    >
      <Glow color={color} />

      <div
        style={{
          opacity: fadeIn(frame, 10, 20),
          transform: `translateY(${slideUp(frame, 10)}px)`,
        }}
      >
        <h2 style={{ fontSize: 48, fontWeight: 700, color, textAlign: "center" }}>
          {title}
        </h2>
        <p
          style={{
            fontSize: 22,
            color: COLORS.grayDark,
            textAlign: "center",
            marginTop: 8,
          }}
        >
          {subtitle}
        </p>
      </div>

      {/* Accent line */}
      <div
        style={{
          width: interpolate(frame, [25, 50], [0, 200], {
            extrapolateLeft: "clamp",
            extrapolateRight: "clamp",
          }),
          height: 3,
          background: `linear-gradient(90deg, transparent, ${color}, transparent)`,
          marginTop: 20,
          borderRadius: 2,
        }}
      />

      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          justifyContent: "center",
          gap: 24,
          marginTop: 60,
          padding: "0 120px",
        }}
      >
        {tools.map((t, i) => (
          <ToolCard
            key={i}
            icon={t.icon}
            name={t.name}
            desc={t.desc}
            color={color}
            index={i}
            baseDelay={45}
          />
        ))}
      </div>
    </AbsoluteFill>
  );
};

/* ═══ MEGA-GEN + CTA ═══ */
const MegaGenScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const btnScale = scaleSpring(frame, fps, 80);
  const glow = pulseGlow(frame, 0.04, 0.3, 0.5);

  const megaTools = ["Schema.org", "llms.txt", "robots.txt", "FAQ", "Source of Truth", "Content"];

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 35,
      }}
    >
      <Glow color={COLORS.violet} />

      {/* Mega-gen card */}
      <div
        style={{
          ...glassCard(0.06),
          padding: "40px 60px",
          textAlign: "center",
          opacity: fadeIn(frame, 10, 25),
          transform: `translateY(${slideUp(frame, 10)}px)`,
          borderColor: `${COLORS.violet}25`,
        }}
      >
        <p style={{ fontSize: 18, color: COLORS.purple, fontWeight: 600, letterSpacing: 3 }}>
          \u26A1 M\u00C9GA-G\u00C9N\u00C9RATION
        </p>
        <p style={{ fontSize: 28, color: COLORS.white, fontWeight: 700, marginTop: 15 }}>
          1 clic = 6 outils g\u00E9n\u00E9r\u00E9s
        </p>
        <p style={{ fontSize: 20, color: COLORS.gray, marginTop: 10 }}>
          Une seule requ\u00EAte Gemini produit tout
        </p>
      </div>

      {/* Tool chips */}
      <div style={{ display: "flex", gap: 14, opacity: fadeIn(frame, 50, 20) }}>
        {megaTools.map((name, i) => {
          const s = scaleSpring(frame, fps, 55 + i * 6);
          return (
            <div
              key={i}
              style={{
                padding: "10px 18px",
                borderRadius: 8,
                border: `1px solid ${COLORS.purple}30`,
                background: `${COLORS.purple}08`,
                fontSize: 15,
                fontWeight: 500,
                color: COLORS.purple,
                transform: `scale(${s})`,
              }}
            >
              {name}
            </div>
          );
        })}
      </div>

      {/* CTA */}
      <div
        style={{
          transform: `scale(${btnScale})`,
          padding: "22px 60px",
          borderRadius: 16,
          background: GRADIENTS.brand,
          boxShadow: `0 0 ${40 + glow * 40}px rgba(168,85,247,${0.3 + glow * 0.3})`,
          marginTop: 10,
        }}
      >
        <p style={{ fontSize: 26, fontWeight: 700, color: COLORS.white, letterSpacing: 2 }}>
          ESSAYER LES OUTILS
        </p>
      </div>

      <p
        style={{
          fontSize: 24,
          fontWeight: 300,
          color: COLORS.gold,
          letterSpacing: 4,
          opacity: fadeIn(frame, 100, 20),
        }}
      >
        citedby.ai
      </p>
    </AbsoluteFill>
  );
};

